UPDATE sentences SET
  ex1 = 'This paper posits that critical pedagogy must account for the socioeconomic context of learners.', ex1_ko = '이 논문은 비판 교육학이 학습자의 사회경제적 맥락을 고려해야 한다고 주장해요.',
