  ex3 = 'She has a terrible headache and can''t concentrate.', ex3_ko = '그녀는 심한 두통이 있어서 집중을 할 수 없어요.',
  ex4 = 'He takes a painkiller whenever he has a headache.', ex4_ko = '그는 두통이 있을 때마다 진통제를 먹어요.',
