  ex3 = 'She has a high fever and needs medicine.', ex3_ko = '그녀는 고열이 있어서 약이 필요해요.',
  ex4 = 'He is staying home because he has a fever.', ex4_ko = '그는 열이 있어서 집에 있어요.',
  ex5 = 'If your fever goes above 39 degrees, call a doctor.', ex5_ko = '열이 39도 이상 오르면 의사에게 전화하세요.'
