UPDATE sentences SET
  ex1 = 'I''ve been feeling unwell for three days.', ex1_ko = '3일째 몸이 안 좋아요.',
  ex2 = 'I''ve been feeling unwell for three days and the symptoms are getting worse.', ex2_ko = '3일째 몸이 안 좋고 증상이 점점 심해지고 있어요.',
  ex3 = 'She''s been feeling unwell since the weekend and hasn''t eaten much.', ex3_ko = '그녀는 주말부터 몸이 안 좋고 많이 먹지 못하고 있어요.',
  ex4 = 'He''s been feeling unwell for three days and decided to see a doctor.', ex4_ko = '그는 3일째 몸이 안 좋아서 의사를 만나기로 했어요.',
  ex5 = 'If you''ve been feeling unwell for more than three days, get checked.', ex5_ko = '3일 이상 몸이 안 좋으면 검진을 받으세요.'
