UPDATE sentences SET
  ex1 = 'Do I need a prescription for this medicine?', ex1_ko = '이 약을 사려면 처방전이 필요한가요?',
  ex2 = 'Do I need a prescription for this medicine, or can I buy it over the counter?', ex2_ko = '이 약에 처방전이 필요한가요, 아니면 처방전 없이 살 수 있나요?',
  ex3 = 'She asked the pharmacist if she needed a prescription for the antibiotic.', ex3_ko = '그녀는 항생제에 처방전이 필요한지 약사에게 물었어요.',
  ex4 = 'He didn''t realize he needed a prescription and came back the next day.', ex4_ko = '그는 처방전이 필요한 줄 몰라서 다음 날 다시 왔어요.',
  ex5 = 'Always check whether you need a prescription before going to the pharmacy.', ex5_ko = '약국에 가기 전에 처방전이 필요한지 항상 확인하세요.'
WHERE id = 's_health_A2_03';

UPDATE sentences SET
  ex1 = 'I''m allergic to penicillin.', ex1_ko = '저는 페니실린 알레르기가 있어요.',
  ex2 = 'I''m allergic to penicillin, so please check the medication before prescribing.', ex2_ko = '저는 페니실린 알레르기가 있으니 처방 전에 약을 확인해 주세요.',
  ex3 = 'She''s allergic to penicillin and carries a medical alert card.', ex3_ko = '그녀는 페니실린 알레르기가 있어서 의료 경보 카드를 갖고 다녀요.',
  ex4 = 'He was allergic to penicillin, so the doctor prescribed a different antibiotic.', ex4_ko = '그는 페니실린 알레르기가 있어서 의사가 다른 항생제를 처방했어요.',
  ex5 = 'If you are allergic to penicillin, always inform your doctor before treatment.', ex5_ko = '페니실린 알레르기가 있다면 치료 전에 항상 의사에게 알리세요.'
WHERE id = 's_health_A2_04';

UPDATE sentences SET
  ex1 = 'How often should I take this medicine?', ex1_ko = '이 약은 얼마나 자주 복용해야 하나요?',
  ex2 = 'How often should I take this medicine, and should I take it with food?', ex2_ko = '이 약은 얼마나 자주 복용해야 하고 식사와 함께 먹어야 하나요?',
  ex3 = 'She asked the pharmacist how often she should take the new medication.', ex3_ko = '그녀는 약사에게 새 약을 얼마나 자주 복용해야 하는지 물었어요.',
  ex4 = 'He forgot how often he should take the medicine and called the clinic to check.', ex4_ko = '그는 약을 얼마나 자주 먹어야 하는지 잊어버려서 확인하려고 클리닉에 전화했어요.',
  ex5 = 'Always read the label to know how often you should take the medicine.', ex5_ko = '약을 얼마나 자주 복용해야 하는지 알려면 항상 라벨을 읽으세요.'
WHERE id = 's_health_A2_05';

UPDATE sentences SET
  ex1 = 'My temperature is 38 degrees.', ex1_ko = '체온이 38도예요.',
  ex2 = 'My temperature is 38 degrees and I feel weak all over.', ex2_ko = '체온이 38도이고 온몸에 힘이 없어요.',
  ex3 = 'Her temperature is 38 degrees and rising, so she needs medication.', ex3_ko = '그녀의 체온이 38도이고 오르고 있어서 약이 필요해요.',
  ex4 = 'His temperature was 38 degrees when he arrived at the clinic.', ex4_ko = '그가 클리닉에 도착했을 때 체온이 38도였어요.',
  ex5 = 'A temperature of 38 degrees or higher is generally considered a fever.', ex5_ko = '38도 이상의 체온은 일반적으로 열로 간주돼요.'
