UPDATE sentences SET
  ex1 = 'Is there a pharmacy near here?', ex1_ko = '이 근처에 약국이 있나요?',
  ex2 = 'Is there a pharmacy near here that is open right now?', ex2_ko = '지금 문을 연 약국이 이 근처에 있나요?',
  ex3 = 'She asked the hotel staff if there was a pharmacy near here.', ex3_ko = '그녀는 호텔 직원에게 이 근처에 약국이 있는지 물었어요.',
  ex4 = 'He looked for a pharmacy near here but couldn''t find one open.', ex4_ko = '그는 근처 약국을 찾았지만 문이 열린 곳을 찾을 수 없었어요.',
  ex5 = 'Use a map app to find the nearest pharmacy if you are not sure where to go.', ex5_ko = '어디로 가야 할지 모를 때는 지도 앱을 사용해 가장 가까운 약국을 찾으세요.'
