  ex2 = 'I''d like to escalate this to a manager, as I''ve been waiting over a week.', ex2_ko = '일주일 이상 기다렸기 때문에 매니저에게 escalate하고 싶어요.',
  ex3 = 'I''d like to escalate this to a manager, as the refund has not been processed.', ex3_ko = '환불이 처리되지 않아서 매니저에게 escalate하고 싶어요.',
  ex4 = 'I''d like to escalate this to a manager, as the staff have been unhelpful.', ex4_ko = '직원들이 도움이 안 돼서 매니저에게 escalate하고 싶어요.',
  ex5 = 'I''d like to escalate this to head office, as the store has not resolved my complaint.', ex5_ko = '매장에서 불만을 해결해 주지 않아서 본사에 escalate하고 싶어요.'
WHERE id = 's_shopping_B2_03';

UPDATE sentences SET
  ex1 = 'I believe I was overcharged. Could you check the receipt?', ex1_ko = '과다 청구된 것 같아요. 영수증을 확인해 주실 수 있나요?',
  ex2 = 'I believe I was charged twice. Could you check the receipt?', ex2_ko = '두 번 청구된 것 같아요. 영수증을 확인해 주실 수 있나요?',
  ex3 = 'I believe the discount wasn''t applied. Could you check the receipt?', ex3_ko = '할인이 적용되지 않은 것 같아요. 영수증을 확인해 주실 수 있나요?',
  ex4 = 'I believe the sale price wasn''t reflected. Could you check the receipt?', ex4_ko = '세일 가격이 반영되지 않은 것 같아요. 영수증을 확인해 주실 수 있나요?',
  ex5 = 'I believe the wrong item was rung up. Could you check the receipt?', ex5_ko = '잘못된 물건이 입력된 것 같아요. 영수증을 확인해 주실 수 있나요?'
WHERE id = 's_shopping_B2_04';

UPDATE sentences SET
  ex1 = 'I''d like a full itemised receipt, including all surcharges.', ex1_ko = '모든 할증료를 포함한 항목별 영수증을 받고 싶어요.',
  ex2 = 'I''d like a full itemised receipt, including the VAT breakdown.', ex2_ko = '부가세 내역을 포함한 항목별 영수증을 받고 싶어요.',
  ex3 = 'I''d like a full itemised receipt for my expense report.', ex3_ko = '경비 보고서를 위해 항목별 영수증을 받고 싶어요.',
  ex4 = 'I''d like a full itemised receipt emailed to me, please.', ex4_ko = '이메일로 항목별 영수증을 받고 싶어요.',
  ex5 = 'I''d like a full itemised receipt showing each item separately.', ex5_ko = '각 품목이 따로 나온 항목별 영수증을 받고 싶어요.'
WHERE id = 's_shopping_B2_05';

UPDATE sentences SET
  ex1 = 'Is there an extended warranty available for this product?', ex1_ko = '이 제품에 대한 연장 보증이 있나요?',
  ex2 = 'Is there an extended warranty available for this appliance?', ex2_ko = '이 가전제품에 대한 연장 보증이 있나요?',
  ex3 = 'Is there an extended warranty I can purchase separately?', ex3_ko = '따로 구매할 수 있는 연장 보증이 있나요?',
  ex4 = 'Is there an extended warranty that covers accidental damage?', ex4_ko = '우발적 손상을 커버하는 연장 보증이 있나요?',
  ex5 = 'Is there an extended warranty if I register the product today?', ex5_ko = '오늘 제품을 등록하면 연장 보증이 있나요?'
WHERE id = 's_shopping_B2_06';

UPDATE sentences SET
  ex1 = 'I''d like to register a formal complaint about the quality of service.', ex1_ko = '서비스 품질에 대해 공식 불만을 제기하고 싶어요.',
  ex2 = 'I''d like to register a formal complaint about the damaged goods I received.', ex2_ko = '받은 파손 물건에 대해 공식 불만을 제기하고 싶어요.',
  ex3 = 'I''d like to register a formal complaint about the misleading advertisement.', ex3_ko = '오해의 소지가 있는 광고에 대해 공식 불만을 제기하고 싶어요.',
  ex4 = 'I''d like to register a formal complaint about the long delay in my refund.', ex4_ko = '환불이 오래 지연되는 것에 대해 공식 불만을 제기하고 싶어요.',
  ex5 = 'I''d like to register a formal complaint about the rude behaviour of staff.', ex5_ko = '직원의 무례한 행동에 대해 공식 불만을 제기하고 싶어요.'
WHERE id = 's_shopping_B2_07';

