UPDATE sentences SET
  ex1 = 'We''re looking for a long-term supplier with a proven track record in quality assurance.', ex1_ko = '품질 보증에 있어서 검증된 실적을 가진 장기 공급업체를 찾고 있어요.',
  ex2 = 'We''re looking for a long-term supplier with experience in sustainable manufacturing.', ex2_ko = '지속 가능한 제조 경험이 있는 장기 공급업체를 찾고 있어요.',
  ex3 = 'We''re looking for a long-term logistics partner with a proven track record in on-time delivery.', ex3_ko = '정시 배송에 있어서 검증된 실적을 가진 장기 물류 파트너를 찾고 있어요.',
  ex4 = 'We''re looking for a long-term distributor with an established network in Southeast Asia.', ex4_ko = '동남아시아에 구축된 네트워크를 가진 장기 유통업체를 찾고 있어요.',
  ex5 = 'We''re looking for a long-term retail partner with a proven ability to manage high-volume orders.', ex5_ko = '대량 주문 관리 능력이 검증된 장기 소매 파트너를 찾고 있어요.'
WHERE id = 's_shopping_C1_01';

UPDATE sentences SET
  ex1 = 'We need to carry out due diligence on your supply chain before finalising the contract.', ex1_ko = '계약을 확정하기 전에 공급망에 대한 실사를 진행해야 해요.',
  ex2 = 'We need to carry out due diligence on your financials before finalising the agreement.', ex2_ko = '계약을 확정하기 전에 재무 상황에 대한 실사를 진행해야 해요.',
  ex3 = 'We need to carry out due diligence on your compliance records before proceeding.', ex3_ko = '진행하기 전에 규정 준수 기록에 대한 실사를 진행해야 해요.',
  ex4 = 'We need to carry out due diligence on all proposed partners before making a decision.', ex4_ko = '결정을 내리기 전에 모든 제안된 파트너에 대한 실사를 진행해야 해요.',
  ex5 = 'We need to carry out due diligence on the intellectual property claims before signing.', ex5_ko = '서명 전에 지식재산권 주장에 대한 실사를 진행해야 해요.'
WHERE id = 's_shopping_C1_02';

UPDATE sentences SET
  ex1 = 'Could you provide a detailed invoice, including a breakdown of costs?', ex1_ko = '비용 내역을 포함한 상세 청구서를 제공해 주실 수 있나요?',
  ex2 = 'Could you provide a detailed invoice showing labour and materials separately?', ex2_ko = '인건비와 자재비를 따로 표시한 상세 청구서를 제공해 주실 수 있나요?',
  ex3 = 'Could you provide a detailed invoice including all taxes and surcharges?', ex3_ko = '모든 세금과 할증료를 포함한 상세 청구서를 제공해 주실 수 있나요?',
  ex4 = 'Could you provide a revised invoice reflecting the agreed discount?', ex4_ko = '합의된 할인을 반영한 수정 청구서를 제공해 주실 수 있나요?',
  ex5 = 'Could you provide a pro-forma invoice ahead of the shipment?', ex5_ko = '선적 전에 견적 청구서를 제공해 주실 수 있나요?'
WHERE id = 's_shopping_C1_03';

UPDATE sentences SET
  ex1 = 'We''d like to discuss volume-based pricing for orders exceeding five thousand units.', ex1_ko = '5천 개를 초과하는 주문에 대한 수량 기반 가격을 논의하고 싶어요.',
  ex2 = 'We''d like to discuss volume-based pricing for our annual procurement contract.', ex2_ko = '연간 조달 계약에 대한 수량 기반 가격을 논의하고 싶어요.',
  ex3 = 'We''d like to discuss tiered pricing that rewards higher order volumes.', ex3_ko = '더 많은 주문량에 보상을 제공하는 단계별 가격을 논의하고 싶어요.',
  ex4 = 'We''d like to discuss a long-term pricing structure that reflects our purchasing commitment.', ex4_ko = '저희 구매 약정을 반영하는 장기 가격 구조를 논의하고 싶어요.',
  ex5 = 'We''d like to discuss volume discounts applicable across all product categories.', ex5_ko = '모든 제품 카테고리에 적용 가능한 수량 할인을 논의하고 싶어요.'
WHERE id = 's_shopping_C1_04';

UPDATE sentences SET
  ex1 = 'Our brand positioning requires suppliers who can demonstrate ethical sourcing practices.', ex1_ko = '저희 브랜드 포지셔닝은 윤리적 조달 관행을 입증할 수 있는 공급업체를 필요로 해요.',
  ex2 = 'Our brand positioning requires partners who share our commitment to sustainability.', ex2_ko = '저희 브랜드 포지셔닝은 지속 가능성에 대한 저희의 의지를 공유하는 파트너를 필요로 해요.',
  ex3 = 'Our brand positioning requires vendors who can meet strict quality standards.', ex3_ko = '저희 브랜드 포지셔닝은 엄격한 품질 기준을 충족할 수 있는 판매업체를 필요로 해요.',
  ex4 = 'Our brand positioning requires manufacturers who can guarantee consistent output.', ex4_ko = '저희 브랜드 포지셔닝은 일관된 생산을 보장할 수 있는 제조업체를 필요로 해요.',
  ex5 = 'Our brand positioning requires distributors with experience in the premium segment.', ex5_ko = '저희 브랜드 포지셔닝은 프리미엄 세그먼트 경험이 있는 유통업체를 필요로 해요.'
WHERE id = 's_shopping_C1_05';

UPDATE sentences SET
  ex1 = 'We''d like to propose a tiered discount structure based on quarterly purchase volumes.', ex1_ko = '분기별 구매 수량에 기반한 단계별 할인 구조를 제안하고 싶어요.',
  ex2 = 'We''d like to propose a tiered pricing model linked to annual revenue milestones.', ex2_ko = '연간 매출 마일스톤과 연계된 단계별 가격 모델을 제안하고 싶어요.',
  ex3 = 'We''d like to propose a performance-based discount structure for this partnership.', ex3_ko = '이 파트너십을 위한 성과 기반 할인 구조를 제안하고 싶어요.',
  ex4 = 'We''d like to propose a volume-based rebate scheme effective from next quarter.', ex4_ko = '다음 분기부터 적용 가능한 수량 기반 리베이트 제도를 제안하고 싶어요.',
  ex5 = 'We''d like to propose a revised pricing structure that reflects our growing order volumes.', ex5_ko = '증가하는 주문 수량을 반영한 수정 가격 구조를 제안하고 싶어요.'
WHERE id = 's_shopping_C1_06';

UPDATE sentences SET
  ex1 = 'We propose a consignment model to reduce your inventory risk while ensuring product availability.', ex1_ko = '재고 위험을 줄이면서 제품 가용성을 보장하기 위해 위탁 판매 모델을 제안해요.',
  ex2 = 'We propose a consignment arrangement that allows you to stock our full range without upfront payment.', ex2_ko = '선불 없이 저희 전체 라인을 재고로 보유할 수 있는 위탁 판매 약정을 제안해요.',
  ex3 = 'We propose a consignment model with quarterly settlement to improve your cash flow.', ex3_ko = '현금 흐름 개선을 위해 분기별 정산이 있는 위탁 판매 모델을 제안해요.',
  ex4 = 'We propose a pilot consignment scheme before committing to a full supply agreement.', ex4_ko = '전체 공급 계약을 체결하기 전에 시범 위탁 판매 제도를 제안해요.',
  ex5 = 'We propose a shared-risk consignment model that benefits both parties in low-demand periods.', ex5_ko = '수요가 낮은 기간에 양측 모두에게 이익이 되는 리스크 공유 위탁 판매 모델을 제안해요.'
WHERE id = 's_shopping_C1_07';

-- ────────────────────────────────────────────────────────────
-- C2
-- ────────────────────────────────────────────────────────────
UPDATE sentences SET
  ex1 = 'The proposed markup structure fails to account for the asymmetric information between the manufacturer and the end retailer.', ex1_ko = '제안된 마크업 구조는 제조업체와 최종 소매업체 간의 정보 비대칭을 고려하지 않아요.',
  ex2 = 'The proposed pricing model fails to account for the asymmetric information between the platform and independent sellers.', ex2_ko = '제안된 가격 모델은 플랫폼과 독립 판매자 간의 정보 비대칭을 고려하지 않아요.',
  ex3 = 'The proposed contract fails to account for the information asymmetry that disadvantages smaller suppliers.', ex3_ko = '제안된 계약은 소규모 공급업체에게 불리한 정보 비대칭을 고려하지 않아요.',
  ex4 = 'The proposed fee structure fails to account for the asymmetric information between the franchisor and franchisees.', ex4_ko = '제안된 수수료 구조는 프랜차이즈 본사와 가맹점 사이의 정보 비대칭을 고려하지 않아요.',
  ex5 = 'The proposed valuation fails to account for the asymmetric information available to institutional versus retail investors.', ex5_ko = '제안된 평가는 기관 투자자와 개인 투자자 간에 가용한 정보 비대칭을 고려하지 않아요.'
WHERE id = 's_shopping_C2_01';

UPDATE sentences SET
  ex1 = 'The cartel-like behaviour among suppliers constitutes a restraint of trade and may attract regulatory scrutiny.', ex1_ko = '공급업체들 간의 카르텔적 행동은 거래 제한에 해당하며 규제 기관의 조사를 받을 수 있어요.',
  ex2 = 'The cartel-like behaviour among dominant platforms constitutes a restraint of trade and may invite antitrust action.', ex2_ko = '지배적 플랫폼들 간의 카르텔적 행동은 거래 제한에 해당하며 독점금지 조치를 불러올 수 있어요.',
  ex3 = 'The cartel-like pricing practices in this sector constitute a restraint of trade and risk significant penalties.', ex3_ko = '이 분야의 카르텔적 가격 책정 관행은 거래 제한에 해당하며 상당한 제재를 받을 위험이 있어요.',
  ex4 = 'Coordinated bidding among contractors constitutes a restraint of trade and may attract criminal prosecution.', ex4_ko = '계약업체들 간의 입찰 담합은 거래 제한에 해당하며 형사 기소를 받을 수 있어요.',
  ex5 = 'Exclusive geographic agreements that partition markets can constitute a restraint of trade under competition law.', ex5_ko = '시장을 분할하는 독점적 지역 협약은 경쟁법상 거래 제한에 해당할 수 있어요.'
WHERE id = 's_shopping_C2_02';

UPDATE sentences SET
  ex1 = 'Commodification of artisan products risks eroding the very brand equity that justifies their premium positioning.', ex1_ko = '장인 제품의 상품화는 프리미엄 포지셔닝을 정당화하는 브랜드 자산 자체를 침식할 위험이 있어요.',
  ex2 = 'Commodification of luxury services risks undermining the exclusivity that sustains premium pricing.', ex2_ko = '럭셔리 서비스의 상품화는 프리미엄 가격을 지탱하는 독점성을 훼손할 위험이 있어요.',
  ex3 = 'Commodification of professional services risks reducing perceived value and intensifying price competition.', ex3_ko = '전문 서비스의 상품화는 인지 가치를 낮추고 가격 경쟁을 심화시킬 위험이 있어요.',
  ex4 = 'Commodification of cultural experiences risks alienating the core audience that defines authenticity.', ex4_ko = '문화 체험의 상품화는 진정성을 정의하는 핵심 관객을 소외시킬 위험이 있어요.',
  ex5 = 'Commodification of healthcare risks prioritising profit over patient welfare and eroding public trust.', ex5_ko = '의료의 상품화는 환자 복지보다 이익을 우선시하고 공공 신뢰를 침식할 위험이 있어요.'
WHERE id = 's_shopping_C2_03';

UPDATE sentences SET
  ex1 = 'We must factor in both the net present value of the contract and potential depreciation of key assets over the agreement.', ex1_ko = '계약의 순현재가치와 계약 기간 동안 핵심 자산의 잠재적 감가상각을 모두 고려해야 해요.',
  ex2 = 'We must factor in both the projected revenue streams and the amortization of upfront investment costs.', ex2_ko = '예상 수익 흐름과 초기 투자 비용의 상각을 모두 고려해야 해요.',
  ex3 = 'We must factor in both the long-term brand equity gains and the short-term margin compression this strategy entails.', ex3_ko = '이 전략이 수반하는 장기적인 브랜드 자산 증가와 단기적인 마진 압박을 모두 고려해야 해요.',
  ex4 = 'We must factor in both the liquidity impact of the acquisition and the solvency risk it creates.', ex4_ko = '인수의 유동성 영향과 그로 인한 지급 능력 위험을 모두 고려해야 해요.',
  ex5 = 'We must factor in both the economies of scale achievable through consolidation and the diseconomies that may emerge at scale.', ex5_ko = '통합을 통해 달성 가능한 규모의 경제와 확장 시 발생할 수 있는 규모의 불경제를 모두 고려해야 해요.'
WHERE id = 's_shopping_C2_04';

UPDATE sentences SET
  ex1 = 'The franchisee''s obligations under the licensing agreement must be reconciled with consumer protection legislation.', ex1_ko = '라이선스 계약에 따른 가맹점의 의무는 소비자 보호 법규와 조화를 이루어야 해요.',
  ex2 = 'The distributor''s obligations under the exclusivity clause must be reconciled with competition law requirements.', ex2_ko = '독점 조항에 따른 유통업체의 의무는 경쟁법 요건과 조화를 이루어야 해요.',
  ex3 = 'The platform''s data obligations under the service contract must be reconciled with privacy regulations.', ex3_ko = '서비스 계약에 따른 플랫폼의 데이터 의무는 개인 정보 보호 법규와 조화를 이루어야 해요.',
  ex4 = 'The manufacturer''s warranty obligations must be reconciled with the statutory rights afforded to consumers.', ex4_ko = '제조업체의 보증 의무는 소비자에게 부여된 법정 권리와 조화를 이루어야 해요.',
  ex5 = 'The supplier''s environmental obligations under the agreement must be reconciled with domestic regulatory standards.', ex5_ko = '계약에 따른 공급업체의 환경 의무는 국내 규제 기준과 조화를 이루어야 해요.'
WHERE id = 's_shopping_C2_05';

UPDATE sentences SET
  ex1 = 'Planned obsolescence strategies, while boosting short-term sales, create negative externalities that increasingly expose brands to reputational and regulatory risk.', ex1_ko = '계획적 노화 전략은 단기 매출을 올리면서도 브랜드를 점점 더 명성 및 규제 위험에 노출시키는 부정적 외부 효과를 만들어요.',
  ex2 = 'Aggressive markdown strategies, while driving short-term volume, create negative externalities that undermine long-term brand equity and margin sustainability.', ex2_ko = '공격적인 가격 인하 전략은 단기 물량을 늘리면서도 장기적인 브랜드 자산과 마진 지속 가능성을 훼손하는 부정적 외부 효과를 만들어요.',
  ex3 = 'Fast fashion production models, while maximising near-term profitability, create negative externalities in the form of textile waste and carbon emissions that regulators are beginning to price in.', ex3_ko = '패스트 패션 생산 모델은 단기 수익을 극대화하면서도 규제 기관들이 가격에 반영하기 시작한 섬유 폐기물과 탄소 배출의 부정적 외부 효과를 만들어요.',
  ex4 = 'Predatory pricing tactics, while rapidly expanding market share, create negative externalities that ultimately harm consumer welfare and invite antitrust intervention.', ex4_ko = '약탈적 가격 책정 전술은 시장 점유율을 빠르게 확장하면서도 결국 소비자 후생을 해치고 독점금지 개입을 초래하는 부정적 외부 효과를 만들어요.',
  ex5 = 'Excessive packaging strategies, while reducing logistics damage, create negative externalities through plastic waste that are increasingly subject to regulatory penalties.', ex5_ko = '과도한 포장 전략은 물류 손상을 줄이면서도 점점 더 규제 제재 대상이 되는 플라스틱 폐기물을 통한 부정적 외부 효과를 만들어요.'
WHERE id = 's_shopping_C2_06';

UPDATE sentences SET
  ex1 = 'As a monopsony buyer, we have significant leverage, but exercising it aggressively risks triggering predatory pricing accusations and antitrust investigations.', ex1_ko = '단일 수요 독점 구매자로서 저희는 상당한 협상력이 있지만, 이를 공격적으로 행사하면 약탈적 가격 책정 혐의와 독점금지 조사를 촉발할 위험이 있어요.',
  ex2 = 'As the dominant platform operator, we hold considerable market power, but exercising it without restraint risks attracting monopoly abuse charges under competition law.', ex2_ko = '지배적 플랫폼 운영자로서 저희는 상당한 시장 지배력이 있지만, 이를 무분별하게 행사하면 경쟁법상 독점 남용 혐의를 받을 위험이 있어요.',
  ex3 = 'As the sole distributor in this territory, we hold substantial leverage over suppliers, but using it to impose below-cost pricing risks regulatory intervention.', ex3_ko = '이 지역의 독점 유통업체로서 저희는 공급업체에 대한 상당한 협상력이 있지만, 이를 이용해 원가 이하 가격을 강요하면 규제 개입의 위험이 있어요.',
  ex4 = 'As a vertically integrated market leader, we enjoy structural advantages, but leveraging these to exclude competitors risks violating antitrust statutes in key jurisdictions.', ex4_ko = '수직 통합 시장 리더로서 저희는 구조적 이점이 있지만, 이를 이용해 경쟁자를 배제하면 주요 관할 구역에서 독점금지법을 위반할 위험이 있어요.',
  ex5 = 'As the largest buyer in this category, we possess significant pricing power, but deploying it to squeeze supplier margins below viability risks destabilising our own supply chain.', ex5_ko = '이 카테고리에서 가장 큰 구매자로서 저희는 상당한 가격 결정력이 있지만, 이를 이용해 공급업체 마진을 생존 한계 이하로 압박하면 자체 공급망을 불안정하게 만들 위험이 있어요.'
WHERE id = 's_shopping_C2_07';

