  ex2 = 'Have you tried restarting the app? That usually fixes it.', ex2_ko = '앱을 다시 시작해 보셨나요? 보통 그걸로 해결돼요.',
  ex3 = 'Have you tried clearing the cache? It might help.', ex3_ko = '캐시를 지워 보셨나요? 도움이 될 수도 있어요.',
  ex4 = 'Have you tried using a different browser?', ex4_ko = '다른 브라우저를 사용해 보셨나요?',
  ex5 = 'Have you tried updating the software? That might fix the problem.', ex5_ko = '소프트웨어를 업데이트해 보셨나요? 문제가 해결될 수도 있어요.'
