UPDATE sentences SET
  ex1 = 'You need to update the software first.', ex1_ko = '먼저 소프트웨어를 업데이트해야 해요.',
  ex2 = 'You need to update the app before you can use this feature.', ex2_ko = '이 기능을 사용하려면 앱을 먼저 업데이트해야 해요.',
  ex3 = 'The system won''t let me proceed until I update.', ex3_ko = '업데이트하기 전까지 시스템이 진행을 허용하지 않아요.',
  ex4 = 'I updated my phone and now some apps won''t open.', ex4_ko = '폰을 업데이트했는데 일부 앱이 열리지 않아요.',
  ex5 = 'It''s important to update your software regularly for security.', ex5_ko = '보안을 위해 소프트웨어를 정기적으로 업데이트하는 것이 중요해요.'
