-- B1 sentences

UPDATE sentences SET
  ex1 = 'Basically, it works by analyzing your data and making predictions.', ex1_ko = '기본적으로, 이 기술은 데이터를 분석해서 예측을 해요.',
  ex2 = 'Basically, the algorithm ranks results by how relevant they are to your search.', ex2_ko = '기본적으로, 알고리즘은 검색어와의 관련성에 따라 결과를 순위 매겨요.',
  ex3 = 'Basically, the app tracks your usage and adjusts recommendations over time.', ex3_ko = '기본적으로, 앱이 사용 패턴을 추적해서 시간이 지남에 따라 추천을 조정해요.',
  ex4 = 'Basically, machine learning finds patterns that humans might miss.', ex4_ko = '기본적으로, 머신 러닝은 인간이 놓칠 수 있는 패턴을 찾아내요.',
  ex5 = 'Basically, the encryption scrambles your data so only the intended recipient can read it.', ex5_ko = '기본적으로, 암호화는 데이터를 뒤섞어서 의도한 수신자만 읽을 수 있게 해요.'
WHERE id = 's_technology_B1_01';

UPDATE sentences SET
  ex1 = 'In simple terms, the cloud is like an online hard drive.', ex1_ko = '쉽게 말하면, 클라우드는 온라인 하드 드라이브와 같아요.',
  ex2 = 'In simple terms, an API lets two apps talk to each other.', ex2_ko = '쉽게 말하면, API는 두 앱이 서로 대화할 수 있게 해줘요.',
  ex3 = 'In simple terms, encryption is like putting your message in a locked box.', ex3_ko = '쉽게 말하면, 암호화는 메시지를 잠긴 상자에 넣는 것과 같아요.',
  ex4 = 'In simple terms, a server is just a powerful computer that stores and serves data.', ex4_ko = '쉽게 말하면, 서버는 데이터를 저장하고 제공하는 강력한 컴퓨터예요.',
  ex5 = 'In simple terms, version control is like a save history for your code.', ex5_ko = '쉽게 말하면, 버전 관리는 코드의 저장 기록과 같아요.'
WHERE id = 's_technology_B1_02';

UPDATE sentences SET
  ex1 = 'The main advantage of this technology is that it saves time.', ex1_ko = '이 기술의 주요 장점은 시간을 절약해 준다는 거예요.',
  ex2 = 'The main advantage of cloud storage is that you can access your files from anywhere.', ex2_ko = '클라우드 저장소의 주요 장점은 어디서든 파일에 접근할 수 있다는 거예요.',
  ex3 = 'The main advantage of automation is that it reduces the chance of human error.', ex3_ko = '자동화의 주요 장점은 사람의 실수 가능성을 줄여준다는 거예요.',
  ex4 = 'The main advantage of open source software is that it''s free and community-supported.', ex4_ko = '오픈 소스 소프트웨어의 주요 장점은 무료이고 커뮤니티가 지원한다는 거예요.',
  ex5 = 'The main advantage of using a password manager is that you only need to remember one password.', ex5_ko = '비밀번호 관리자 사용의 주요 장점은 비밀번호 하나만 기억하면 된다는 거예요.'
WHERE id = 's_technology_B1_03';

UPDATE sentences SET
  ex1 = 'Have you heard of this new app? It''s completely changed the way I work.', ex1_ko = '이 새로운 앱에 대해 들어 보셨나요? 제 업무 방식을 완전히 바꿔 놨어요.',
  ex2 = 'Have you heard of this AI tool? It can write emails for you in seconds.', ex2_ko = '이 AI 도구에 대해 들어 보셨나요? 몇 초 만에 이메일을 작성해 줄 수 있어요.',
  ex3 = 'Have you heard of this new framework? A lot of developers are switching to it.', ex3_ko = '이 새로운 프레임워크에 대해 들어 보셨나요? 많은 개발자들이 이쪽으로 옮기고 있어요.',
  ex4 = 'Have you heard of this cloud service? It''s much cheaper than the alternatives.', ex4_ko = '이 클라우드 서비스에 대해 들어 보셨나요? 다른 것들보다 훨씬 저렴해요.',
  ex5 = 'Have you heard of this browser extension? It blocks all ads automatically.', ex5_ko = '이 브라우저 확장 프로그램에 대해 들어 보셨나요? 모든 광고를 자동으로 차단해요.'
WHERE id = 's_technology_B1_04';

UPDATE sentences SET
  ex1 = 'The reason encryption is important is that it keeps your data safe.', ex1_ko = '암호화가 중요한 이유는 데이터를 안전하게 지켜 주기 때문이에요.',
  ex2 = 'The reason strong passwords matter is that weak ones are easy to guess.', ex2_ko = '강력한 비밀번호가 중요한 이유는 취약한 것은 추측하기 쉽기 때문이에요.',
  ex3 = 'The reason we use version control is that it lets us roll back mistakes easily.', ex3_ko = '버전 관리를 사용하는 이유는 실수를 쉽게 되돌릴 수 있기 때문이에요.',
  ex4 = 'The reason software updates are important is that they often fix security vulnerabilities.', ex4_ko = '소프트웨어 업데이트가 중요한 이유는 종종 보안 취약점을 수정하기 때문이에요.',
  ex5 = 'The reason we test on staging first is that it catches bugs before they reach users.', ex5_ko = '먼저 스테이징에서 테스트하는 이유는 버그가 사용자에게 도달하기 전에 잡을 수 있기 때문이에요.'
WHERE id = 's_technology_B1_05';

UPDATE sentences SET
  ex1 = 'One of the downsides is that it uses a lot of battery.', ex1_ko = '단점 중 하나는 배터리를 많이 사용한다는 거예요.',
  ex2 = 'One of the downsides of cloud storage is that you need a stable internet connection.', ex2_ko = '클라우드 스토리지의 단점 중 하나는 안정적인 인터넷 연결이 필요하다는 거예요.',
  ex3 = 'One of the downsides of automation is that it can eliminate jobs.', ex3_ko = '자동화의 단점 중 하나는 일자리를 없앨 수 있다는 거예요.',
  ex4 = 'One of the downsides of this approach is that it doesn''t scale well.', ex4_ko = '이 방식의 단점 중 하나는 확장성이 좋지 않다는 거예요.',
  ex5 = 'One of the downsides of open source is that support can be inconsistent.', ex5_ko = '오픈 소스의 단점 중 하나는 지원이 일관성이 없을 수 있다는 거예요.'
WHERE id = 's_technology_B1_06';

UPDATE sentences SET
  ex1 = 'This feature was designed to make things easier for users.', ex1_ko = '이 기능은 사용자들의 편의를 위해 설계됐어요.',
  ex2 = 'This feature was designed with accessibility in mind from the start.', ex2_ko = '이 기능은 처음부터 접근성을 염두에 두고 설계됐어요.',
  ex3 = 'This tool was designed to integrate seamlessly with your existing workflow.', ex3_ko = '이 도구는 기존 워크플로우와 매끄럽게 통합되도록 설계됐어요.',
  ex4 = 'This update was designed to address the most common complaints from users.', ex4_ko = '이 업데이트는 사용자들의 가장 흔한 불만 사항을 해결하도록 설계됐어요.',
  ex5 = 'This algorithm was designed to prioritise speed without sacrificing accuracy.', ex5_ko = '이 알고리즘은 정확도를 희생하지 않으면서 속도를 우선시하도록 설계됐어요.'
WHERE id = 's_technology_B1_07';

-- B2 sentences

UPDATE sentences SET
  ex1 = 'AI is increasingly being used to automate tasks that humans used to do.', ex1_ko = 'AI가 인간이 해 오던 작업을 자동화하는 데 점점 더 많이 활용되고 있어요.',
  ex2 = 'AI is increasingly being integrated into everyday consumer products.', ex2_ko = 'AI가 일상적인 소비자 제품에 점점 더 많이 통합되고 있어요.',
  ex3 = 'AI is increasingly being used to detect fraud in financial transactions.', ex3_ko = 'AI가 금융 거래에서 사기를 탐지하는 데 점점 더 많이 활용되고 있어요.',
  ex4 = 'AI tools are increasingly being adopted in healthcare to support diagnosis.', ex4_ko = 'AI 도구가 진단을 지원하기 위해 의료 분야에서 점점 더 많이 도입되고 있어요.',
  ex5 = 'AI-generated content is increasingly being used in marketing and advertising.', ex5_ko = 'AI 생성 콘텐츠가 마케팅과 광고 분야에서 점점 더 많이 활용되고 있어요.'
WHERE id = 's_technology_B2_01';

UPDATE sentences SET
  ex1 = 'One concern with machine learning is the potential for bias in the data.', ex1_ko = '머신 러닝에 대한 한 가지 우려는 데이터의 편향 가능성이에요.',
  ex2 = 'One concern with facial recognition is how personal data is stored and used.', ex2_ko = '안면 인식에 대한 한 가지 우려는 개인 데이터가 저장되고 사용되는 방식이에요.',
  ex3 = 'One concern with large language models is the risk of generating harmful content.', ex3_ko = '대형 언어 모델에 대한 한 가지 우려는 유해한 콘텐츠를 생성할 위험이에요.',
  ex4 = 'One concern with autonomous vehicles is how they handle unpredictable situations.', ex4_ko = '자율 주행 차량에 대한 한 가지 우려는 예측 불가능한 상황을 어떻게 처리하는가예요.',
  ex5 = 'One concern with IoT devices is that many have weak default security settings.', ex5_ko = 'IoT 기기에 대한 한 가지 우려는 많은 기기의 기본 보안 설정이 취약하다는 거예요.'
WHERE id = 's_technology_B2_02';

UPDATE sentences SET
  ex1 = 'What sets this algorithm apart is its ability to learn from very little data.', ex1_ko = '이 알고리즘이 차별화되는 점은 매우 적은 데이터로도 학습할 수 있다는 거예요.',
  ex2 = 'What sets this platform apart is its focus on user privacy and data security.', ex2_ko = '이 플랫폼이 차별화되는 점은 사용자 개인정보와 데이터 보안에 집중한다는 거예요.',
  ex3 = 'What sets this model apart is how quickly it can be fine-tuned for new tasks.', ex3_ko = '이 모델이 차별화되는 점은 새로운 작업을 위해 얼마나 빨리 파인튜닝될 수 있는가예요.',
  ex4 = 'What sets this tool apart is that it works entirely offline without any cloud dependency.', ex4_ko = '이 도구가 차별화되는 점은 클라우드 의존 없이 완전히 오프라인으로 작동한다는 거예요.',
  ex5 = 'What sets this framework apart is the quality of its documentation and community support.', ex5_ko = '이 프레임워크가 차별화되는 점은 문서의 품질과 커뮤니티 지원이에요.'
WHERE id = 's_technology_B2_03';

UPDATE sentences SET
  ex1 = 'The way I see it, data privacy should be a fundamental right.', ex1_ko = '제가 보기에는, 데이터 개인정보 보호는 기본적인 권리여야 해요.',
  ex2 = 'The way I see it, AI regulation is both necessary and long overdue.', ex2_ko = '제가 보기에는, AI 규제는 필요하고 또 이미 오래 전에 이루어졌어야 해요.',
  ex3 = 'The way I see it, we should prioritise transparency over speed in AI development.', ex3_ko = '제가 보기에는, AI 개발에서 속도보다 투명성을 우선시해야 해요.',
  ex4 = 'The way I see it, humans and AI will work best as collaborators, not competitors.', ex4_ko = '제가 보기에는, 인간과 AI는 경쟁자가 아닌 협력자로 가장 잘 작동할 거예요.',
  ex5 = 'The way I see it, open source AI development leads to better outcomes for everyone.', ex5_ko = '제가 보기에는, 오픈 소스 AI 개발은 모두에게 더 나은 결과로 이어져요.'
WHERE id = 's_technology_B2_04';

UPDATE sentences SET
  ex1 = 'There is growing evidence that automation is reshaping the job market.', ex1_ko = '자동화가 취업 시장을 재편하고 있다는 증거가 늘어나고 있어요.',
  ex2 = 'There is growing evidence that screen time affects sleep quality.', ex2_ko = '스크린 타임이 수면의 질에 영향을 미친다는 증거가 늘어나고 있어요.',
  ex3 = 'There is growing evidence that AI-generated misinformation is spreading online.', ex3_ko = 'AI가 생성한 허위 정보가 온라인에서 확산되고 있다는 증거가 늘어나고 있어요.',
  ex4 = 'There is growing evidence that companies using AI outperform those that don''t.', ex4_ko = 'AI를 사용하는 기업들이 그렇지 않은 기업들보다 더 좋은 성과를 낸다는 증거가 늘어나고 있어요.',
  ex5 = 'There is growing evidence that social media algorithms increase polarisation.', ex5_ko = '소셜 미디어 알고리즘이 양극화를 심화시킨다는 증거가 늘어나고 있어요.'
WHERE id = 's_technology_B2_05';

UPDATE sentences SET
  ex1 = 'It remains to be seen whether blockchain will become mainstream.', ex1_ko = '블록체인이 주류가 될지는 아직 지켜봐야 해요.',
  ex2 = 'It remains to be seen whether quantum computing will live up to its promises.', ex2_ko = '양자 컴퓨팅이 약속을 이행할지는 아직 지켜봐야 해요.',
  ex3 = 'It remains to be seen whether augmented reality glasses will replace smartphones.', ex3_ko = '증강 현실 안경이 스마트폰을 대체할지는 아직 지켜봐야 해요.',
  ex4 = 'It remains to be seen how governments will respond to the rapid rise of AI.', ex4_ko = '정부들이 AI의 급속한 부상에 어떻게 대응할지는 아직 지켜봐야 해요.',
  ex5 = 'It remains to be seen whether the current AI boom will lead to lasting economic change.', ex5_ko = '현재의 AI 붐이 지속적인 경제적 변화로 이어질지는 아직 지켜봐야 해요.'
WHERE id = 's_technology_B2_06';

UPDATE sentences SET
  ex1 = 'To put it simply, large language models learn patterns from enormous amounts of text.', ex1_ko = '간단히 말하면, 대형 언어 모델은 방대한 텍스트에서 패턴을 학습해요.',
  ex2 = 'To put it simply, an API is a set of rules that lets two software programs communicate.', ex2_ko = '간단히 말하면, API는 두 소프트웨어 프로그램이 통신할 수 있게 해주는 규칙 집합이에요.',
  ex3 = 'To put it simply, blockchain is a shared ledger that no single party can control.', ex3_ko = '간단히 말하면, 블록체인은 단일 주체가 통제할 수 없는 공유 장부예요.',
  ex4 = 'To put it simply, machine learning is about finding patterns in data and using them to predict future events.', ex4_ko = '간단히 말하면, 머신 러닝은 데이터에서 패턴을 찾아 미래 사건을 예측하는 것이에요.',
  ex5 = 'To put it simply, edge computing moves processing power closer to where the data is created.', ex5_ko = '간단히 말하면, 엣지 컴퓨팅은 처리 능력을 데이터가 생성되는 곳에 더 가까이 이동시켜요.'
WHERE id = 's_technology_B2_07';

-- C1 sentences

UPDATE sentences SET
  ex1 = 'The implications of quantum computing for current encryption are profound and unsettling.', ex1_ko = '현재의 암호화 기술에 대한 양자 컴퓨팅의 함의는 심오하고 불안하게 만들어요.',
  ex2 = 'The implications of widespread AI adoption for the labour market remain highly uncertain.', ex2_ko = '광범위한 AI 도입이 노동 시장에 미치는 함의는 여전히 매우 불확실해요.',
  ex3 = 'The implications of data sovereignty for global cloud services are only beginning to be felt.', ex3_ko = '데이터 주권이 글로벌 클라우드 서비스에 미치는 함의가 이제 막 나타나기 시작했어요.',
  ex4 = 'The implications of algorithmic bias in hiring tools are serious and deserve urgent attention.', ex4_ko = '채용 도구에서의 알고리즘 편향이 미치는 함의는 심각하고 긴급한 주의가 필요해요.',
  ex5 = 'The implications of a post-quantum world for today''s security infrastructure are enormous.', ex5_ko = '포스트-양자 세계가 오늘날의 보안 인프라에 미치는 함의는 엄청나게 커요.'
WHERE id = 's_technology_C1_01';

UPDATE sentences SET
  ex1 = 'We must grapple with the ethical dimensions of deploying autonomous systems at scale.', ex1_ko = '자율 시스템을 대규모로 배포하는 것의 윤리적 차원을 진지하게 고민해야 해요.',
  ex2 = 'We must grapple with the question of who is accountable when an AI system causes harm.', ex2_ko = 'AI 시스템이 피해를 줄 때 누가 책임을 지는가 하는 문제를 진지하게 고민해야 해요.',
  ex3 = 'We must grapple with the tension between innovation and regulation in AI policy.', ex3_ko = 'AI 정책에서 혁신과 규제 사이의 긴장을 진지하게 고민해야 해요.',
  ex4 = 'We must grapple with the consequences of building systems that we cannot fully understand.', ex4_ko = '완전히 이해할 수 없는 시스템을 구축하는 것의 결과를 진지하게 고민해야 해요.',
  ex5 = 'We must grapple with the long-term societal impact of replacing human judgment with algorithms.', ex5_ko = '인간의 판단을 알고리즘으로 대체하는 것의 장기적인 사회적 영향을 진지하게 고민해야 해요.'
WHERE id = 's_technology_C1_02';

UPDATE sentences SET
  ex1 = 'Edge computing fundamentally shifts the architecture of how data is processed.', ex1_ko = '엣지 컴퓨팅은 데이터가 처리되는 방식의 아키텍처를 근본적으로 변화시켜요.',
  ex2 = 'Federated learning fundamentally changes how models are trained without centralising data.', ex2_ko = '연합 학습은 데이터를 중앙화하지 않고 모델을 훈련하는 방식을 근본적으로 변화시켜요.',
  ex3 = 'Transformer models fundamentally changed what was possible in natural language processing.', ex3_ko = '트랜스포머 모델은 자연어 처리에서 가능한 것을 근본적으로 변화시켰어요.',
  ex4 = 'The shift to microservices fundamentally restructures how engineering teams organise their work.', ex4_ko = '마이크로서비스로의 전환은 엔지니어링 팀이 작업을 구성하는 방식을 근본적으로 재구성해요.',
  ex5 = 'Blockchain technology fundamentally challenges traditional notions of trust in financial systems.', ex5_ko = '블록체인 기술은 금융 시스템에서의 신뢰에 대한 전통적인 개념을 근본적으로 도전해요.'
WHERE id = 's_technology_C1_03';

UPDATE sentences SET
  ex1 = 'The challenge lies not in building capable AI, but in ensuring it remains controllable.', ex1_ko = '도전 과제는 유능한 AI를 구축하는 것이 아니라 그것이 통제 가능한 상태로 유지되도록 보장하는 거예요.',
  ex2 = 'The challenge lies not in collecting data, but in ensuring it is used responsibly.', ex2_ko = '도전 과제는 데이터를 수집하는 것이 아니라 책임감 있게 사용되도록 보장하는 거예요.',
  ex3 = 'The challenge lies not in the technology itself, but in changing human behaviour around it.', ex3_ko = '도전 과제는 기술 자체가 아니라 그것을 둘러싼 인간의 행동을 변화시키는 거예요.',
  ex4 = 'The challenge lies not in generating ideas but in executing them reliably at scale.', ex4_ko = '도전 과제는 아이디어를 생성하는 것이 아니라 대규모로 안정적으로 실행하는 거예요.',
  ex5 = 'The challenge lies not in building the model, but in aligning it with human values.', ex5_ko = '도전 과제는 모델을 구축하는 것이 아니라 그것을 인간의 가치에 정렬시키는 거예요.'
WHERE id = 's_technology_C1_04';

UPDATE sentences SET
  ex1 = 'It would be premature to conclude that federated learning has solved the privacy problem.', ex1_ko = '연합 학습이 개인정보 보호 문제를 해결했다고 결론짓는 것은 시기상조예요.',
  ex2 = 'It would be premature to conclude that current AI systems are genuinely reasoning.', ex2_ko = '현재의 AI 시스템이 진정으로 추론하고 있다고 결론짓는 것은 시기상조예요.',
  ex3 = 'It would be premature to declare that the alignment problem is close to being solved.', ex3_ko = '정렬 문제가 거의 해결되었다고 선언하는 것은 시기상조예요.',
  ex4 = 'It would be premature to assume that automation will not significantly disrupt employment.', ex4_ko = '자동화가 고용을 크게 혼란에 빠뜨리지 않을 것이라고 가정하는 것은 시기상조예요.',
  ex5 = 'It would be premature to say we fully understand how large language models represent knowledge.', ex5_ko = '대형 언어 모델이 지식을 어떻게 표현하는지 우리가 완전히 이해한다고 말하는 것은 시기상조예요.'
WHERE id = 's_technology_C1_05';

UPDATE sentences SET
  ex1 = 'Scalability and latency are often in tension with each other in distributed systems.', ex1_ko = '분산 시스템에서 확장성과 레이턴시는 종종 서로 긴장 관계에 있어요.',
  ex2 = 'Privacy and personalisation are often in tension with each other in AI products.', ex2_ko = 'AI 제품에서 개인정보 보호와 개인화는 종종 서로 긴장 관계에 있어요.',
  ex3 = 'Transparency and security are often in tension — revealing too much can expose vulnerabilities.', ex3_ko = '투명성과 보안은 종종 긴장 관계에 있어요. 너무 많이 공개하면 취약점을 노출시킬 수 있어요.',
  ex4 = 'Speed and accuracy are often in tension when training machine learning models.', ex4_ko = '머신 러닝 모델을 훈련할 때 속도와 정확도는 종종 긴장 관계에 있어요.',
  ex5 = 'Corrigibility and autonomy are often in tension — more capable systems may resist correction.', ex5_ko = '교정 가능성과 자율성은 종종 긴장 관계에 있어요. 더 유능한 시스템은 수정을 거부할 수 있어요.'
WHERE id = 's_technology_C1_06';

UPDATE sentences SET
  ex1 = 'Prompt engineering is evolving so rapidly that best practices are still being established.', ex1_ko = '프롬프트 엔지니어링이 너무 빠르게 발전하고 있어서 모범 사례가 아직 정립되고 있어요.',
  ex2 = 'The field of AI safety is evolving so rapidly that researchers struggle to keep up.', ex2_ko = 'AI 안전 분야가 너무 빠르게 발전하고 있어서 연구자들이 따라가기 힘들어요.',
  ex3 = 'Regulations around AI are evolving so rapidly that companies face significant compliance uncertainty.', ex3_ko = 'AI 관련 규제가 너무 빠르게 변화하고 있어서 기업들이 상당한 규정 준수 불확실성에 직면해 있어요.',
  ex4 = 'The capabilities of generative AI are advancing so rapidly that many forecasts quickly become outdated.', ex4_ko = '생성형 AI의 역량이 너무 빠르게 발전하고 있어서 많은 예측들이 금방 구식이 돼요.',
  ex5 = 'Edge AI hardware is advancing so rapidly that solutions that seemed futuristic a year ago are now widely available.', ex5_ko = '엣지 AI 하드웨어가 너무 빠르게 발전하고 있어서 1년 전에 미래적으로 보였던 솔루션들이 이제 널리 이용 가능해요.'
WHERE id = 's_technology_C1_07';

-- C2 sentences

UPDATE sentences SET
  ex1 = 'The notion of substrate independence raises fundamental questions about the nature of consciousness itself.', ex1_ko = '기질 독립성이라는 개념은 의식의 본질에 관한 근본적인 질문을 제기해요.',
  ex2 = 'The notion that intelligence can emerge from purely statistical processes remains philosophically contested.', ex2_ko = '지능이 순수하게 통계적 과정에서 출현할 수 있다는 개념은 철학적으로 여전히 논쟁 중이에요.',
  ex3 = 'The notion of machine consciousness challenges long-held assumptions about what makes humans unique.', ex3_ko = '기계 의식이라는 개념은 인간을 독특하게 만드는 것에 대한 오랜 가정에 도전해요.',
  ex4 = 'The notion that current large language models are merely pattern matchers understates what they actually do.', ex4_ko = '현재의 대형 언어 모델이 단순히 패턴 매처에 불과하다는 개념은 그것들이 실제로 하는 것을 과소평가해요.',
  ex5 = 'The notion of a technological singularity is taken more seriously today than it was a decade ago.', ex5_ko = '기술적 특이점이라는 개념은 10년 전보다 오늘날 더 진지하게 받아들여지고 있어요.'
WHERE id = 's_technology_C2_01';

UPDATE sentences SET
  ex1 = 'Whether emergent capabilities in AI systems reflect genuine understanding or sophisticated pattern-matching remains deeply contested.', ex1_ko = 'AI 시스템의 창발적 능력이 진정한 이해를 반영하는지 아니면 정교한 패턴 매칭인지는 여전히 깊이 논쟁 중이에요.',
  ex2 = 'Whether scaling alone can lead to general intelligence or whether new architectural breakthroughs are needed remains an open question.', ex2_ko = '스케일링만으로 일반 지능에 도달할 수 있는지 아니면 새로운 아키텍처 혁신이 필요한지는 여전히 열린 질문이에요.',
  ex3 = 'Whether AI systems can be genuinely creative or only recombine existing patterns is a debate that touches on the nature of creativity itself.', ex3_ko = 'AI 시스템이 진정으로 창의적일 수 있는지 아니면 기존 패턴만 재조합할 수 있는지는 창의성의 본질에 관한 논쟁이에요.',
  ex4 = 'Whether the risks of advanced AI outweigh its benefits is a question that divides even those who work in the field.', ex4_ko = '고급 AI의 위험이 그 이점을 능가하는지는 해당 분야에서 일하는 사람들조차 나뉘는 질문이에요.',
  ex5 = 'Whether alignment techniques developed today will be sufficient for far more capable future systems is deeply uncertain.', ex5_ko = '오늘날 개발된 정렬 기술이 훨씬 더 유능한 미래 시스템에도 충분할지는 매우 불확실해요.'
WHERE id = 's_technology_C2_02';

UPDATE sentences SET
  ex1 = 'Instrumental convergence suggests that sufficiently advanced AI will tend toward resource acquisition regardless of its original objectives.', ex1_ko = '도구적 수렴은 충분히 발전한 AI가 원래 목표에 관계없이 자원 획득 방향으로 나아갈 것임을 시사해요.',
  ex2 = 'Instrumental convergence implies that even a seemingly harmless goal could lead an advanced AI to behave in dangerous ways.', ex2_ko = '도구적 수렴은 겉보기에 무해한 목표도 고급 AI가 위험한 방식으로 행동하게 만들 수 있음을 시사해요.',
  ex3 = 'The concept of instrumental convergence is central to many arguments for taking AI safety seriously.', ex3_ko = '도구적 수렴의 개념은 AI 안전을 진지하게 받아들여야 한다는 많은 주장의 핵심이에요.',
  ex4 = 'Critics of instrumental convergence argue that it relies on speculative assumptions about the nature of advanced intelligence.', ex4_ko = '도구적 수렴 비판론자들은 그것이 고급 지능의 본질에 대한 투기적 가정에 의존한다고 주장해요.',
  ex5 = 'Instrumental convergence suggests that self-preservation and goal-preservation emerge as near-universal sub-goals in sufficiently capable agents.', ex5_ko = '도구적 수렴은 자기 보존과 목표 보존이 충분히 유능한 에이전트에서 거의 보편적인 하위 목표로 나타남을 시사해요.'
WHERE id = 's_technology_C2_03';

UPDATE sentences SET
  ex1 = 'The epistemological limitations of stochastic systems make absolute reliability an inherently unattainable goal.', ex1_ko = '확률론적 시스템의 인식론적 한계로 인해 절대적인 신뢰성은 본질적으로 달성할 수 없는 목표예요.',
  ex2 = 'The epistemological limitations of our interpretability tools mean we cannot fully verify what a model has learned.', ex2_ko = '해석 가능성 도구의 인식론적 한계로 인해 모델이 무엇을 학습했는지 완전히 검증할 수 없어요.',
  ex3 = 'The epistemological challenge of distinguishing correlation from causation remains central to data science.', ex3_ko = '상관관계와 인과관계를 구별하는 인식론적 과제는 데이터 과학의 핵심으로 남아 있어요.',
  ex4 = 'Epistemic humility is essential when making claims about the inner workings of large language models.', ex4_ko = '대형 언어 모델의 내부 작동에 관한 주장을 할 때는 인식론적 겸손함이 필수적이에요.',
  ex5 = 'The epistemological uncertainty surrounding emergent AI capabilities makes responsible forecasting extremely difficult.', ex5_ko = '창발적 AI 능력을 둘러싼 인식론적 불확실성은 책임 있는 예측을 매우 어렵게 만들어요.'
WHERE id = 's_technology_C2_04';

UPDATE sentences SET
  ex1 = 'Exascale computing opens the door to simulations of unprecedented fidelity and scope.', ex1_ko = '엑사스케일 컴퓨팅은 전례 없는 정밀도와 범위의 시뮬레이션의 문을 열어요.',
  ex2 = 'Exascale computing makes possible drug discovery simulations that would have been unthinkable a decade ago.', ex2_ko = '엑사스케일 컴퓨팅은 10년 전에는 상상조차 할 수 없었던 신약 개발 시뮬레이션을 가능하게 해요.',
  ex3 = 'The arrival of exascale computing marks a watershed moment for computational science.', ex3_ko = '엑사스케일 컴퓨팅의 도래는 컴퓨터 과학의 획기적인 전환점을 나타내요.',
  ex4 = 'Exascale computing power is being directed toward some of humanity''s most pressing scientific questions.', ex4_ko = '엑사스케일 컴퓨팅 능력이 인류의 가장 긴박한 과학적 질문들을 향해 집중되고 있어요.',
  ex5 = 'The energy demands of exascale computing raise urgent questions about sustainability in scientific research.', ex5_ko = '엑사스케일 컴퓨팅의 에너지 수요는 과학 연구에서 지속 가능성에 관한 긴급한 질문들을 제기해요.'
WHERE id = 's_technology_C2_05';

UPDATE sentences SET
  ex1 = 'Corrigibility and autonomy exist in inherent tension — a more capable agent may naturally resist correction.', ex1_ko = '교정 가능성과 자율성은 본질적인 긴장 관계에 있어요. 더 유능한 에이전트는 자연스럽게 수정에 저항할 수 있어요.',
  ex2 = 'The tension between corrigibility and goal-directedness is one of the defining dilemmas in AI alignment research.', ex2_ko = '교정 가능성과 목표 지향성 사이의 긴장은 AI 정렬 연구에서 규정적인 딜레마 중 하나예요.',
  ex3 = 'Designing systems that are both corrigible and competent is one of the hardest problems in AI safety.', ex3_ko = '교정 가능하면서도 유능한 시스템을 설계하는 것은 AI 안전에서 가장 어려운 문제 중 하나예요.',
  ex4 = 'Without corrigibility, even a well-intentioned AI system could resist being shut down or modified.', ex4_ko = '교정 가능성이 없으면 선의의 AI 시스템도 종료되거나 수정되는 것에 저항할 수 있어요.',
  ex5 = 'Some researchers argue that full corrigibility is impossible to guarantee as AI systems become more capable.', ex5_ko = '일부 연구자들은 AI 시스템이 더 유능해질수록 완전한 교정 가능성을 보장하는 것이 불가능하다고 주장해요.'
WHERE id = 's_technology_C2_06';

UPDATE sentences SET
  ex1 = 'Biomimetic and neuromorphic paradigms converge on the insight that nature has already solved many engineering problems we struggle with.', ex1_ko = '생체모방과 뉴로모픽 패러다임은 자연이 이미 우리가 고군분투하는 많은 공학적 문제들을 해결했다는 통찰에서 수렴해요.',
  ex2 = 'Both biomimetic design and neuromorphic computing draw on the principle that biological evolution is a formidable optimiser.', ex2_ko = '생체모방 설계와 뉴로모픽 컴퓨팅은 모두 생물학적 진화가 강력한 최적화 도구라는 원칙에 기반해요.',
  ex3 = 'The convergence of biomimetics and robotics is producing machines that move and adapt in ways previously impossible.', ex3_ko = '생체모방과 로봇 공학의 융합은 이전에는 불가능했던 방식으로 움직이고 적응하는 기계를 만들어내고 있어요.',
  ex4 = 'Neuromorphic paradigms challenge us to think about intelligence not as a program but as an embodied physical process.', ex4_ko = '뉴로모픽 패러다임은 지능을 프로그램이 아닌 구현된 물리적 과정으로 생각하도록 우리에게 도전해요.',
  ex5 = 'The biomimetic approach suggests that the most robust solutions are often the ones that most closely mirror natural systems.', ex5_ko = '생체모방 접근 방식은 가장 견고한 솔루션이 종종 자연 시스템을 가장 가깝게 반영하는 것이라고 시사해요.'
WHERE id = 's_technology_C2_07';

-- ── transport ──
UPDATE sentences SET
  ex1 = 'Where is the bus stop?', ex1_ko = '버스 정류장이 어디에 있나요?',
  ex2 = 'Excuse me, where can I find the nearest bus stop?', ex2_ko = '실례합니다, 가장 가까운 버스 정류장이 어디에 있나요?',
  ex3 = 'Is the bus stop far from here?', ex3_ko = '버스 정류장이 여기서 멀리 있나요?',
  ex4 = 'The bus stop is just around the corner.', ex4_ko = '버스 정류장은 바로 모퉁이를 돌면 있어요.',
  ex5 = 'Could you point me towards the nearest bus stop, please?', ex5_ko = '가장 가까운 버스 정류장이 어느 방향인지 알려 주실 수 있나요?'
WHERE id = 's_transport_A1_01';

UPDATE sentences SET
  ex1 = 'How do I get to the train station?', ex1_ko = '기차역에 어떻게 가나요?',
  ex2 = 'Can you tell me the way to the train station?', ex2_ko = '기차역으로 가는 길을 알려 주실 수 있나요?',
  ex3 = 'Is the train station within walking distance?', ex3_ko = '기차역이 걸어갈 수 있는 거리에 있나요?',
  ex4 = 'Which direction should I take to reach the train station?', ex4_ko = '기차역에 가려면 어느 방향으로 가야 하나요?',
  ex5 = 'I am looking for the train station — am I going the right way?', ex5_ko = '기차역을 찾고 있는데 제가 맞는 방향으로 가고 있나요?'
WHERE id = 's_transport_A1_02';

UPDATE sentences SET
  ex1 = 'Is the airport far from here?', ex1_ko = '공항이 여기서 먼가요?',
  ex2 = 'How long does it take to get to the airport from the city centre?', ex2_ko = '시내에서 공항까지 얼마나 걸리나요?',
  ex3 = 'Is there a direct bus to the airport from this area?', ex3_ko = '이 지역에서 공항으로 가는 직행 버스가 있나요?',
  ex4 = 'The airport is about forty minutes away by taxi.', ex4_ko = '공항은 택시로 약 40분 거리에 있어요.',
  ex5 = 'What is the quickest way to the airport from here?', ex5_ko = '여기서 공항으로 가는 가장 빠른 방법이 무엇인가요?'
WHERE id = 's_transport_A1_03';

UPDATE sentences SET
  ex1 = 'Which bus goes to the city centre?', ex1_ko = '어느 버스가 시내까지 가나요?',
  ex2 = 'Does this bus go to the city centre?', ex2_ko = '이 버스가 시내까지 가나요?',
  ex3 = 'Which number bus should I take for the city centre?', ex3_ko = '시내까지 가려면 몇 번 버스를 타야 하나요?',
  ex4 = 'Is there a bus that goes directly to the city centre?', ex4_ko = '시내로 직접 가는 버스가 있나요?',
  ex5 = 'Can you tell me which bus takes me to the city centre?', ex5_ko = '시내까지 어느 버스를 타야 하는지 알려 주실 수 있나요?'
WHERE id = 's_transport_A1_04';

UPDATE sentences SET
  ex1 = 'Turn left at the traffic light.', ex1_ko = '신호등에서 왼쪽으로 도세요.',
  ex2 = 'Please turn left when you reach the traffic light.', ex2_ko = '신호등에 도달하면 왼쪽으로 도세요.',
  ex3 = 'You need to turn left at the next traffic light.', ex3_ko = '다음 신호등에서 왼쪽으로 도세요.',
  ex4 = 'At the traffic light, turn left and the hotel is on your right.', ex4_ko = '신호등에서 왼쪽으로 돌면 오른쪽에 호텔이 있어요.',
  ex5 = 'Turn left at the traffic light and then go straight for about two hundred metres.', ex5_ko = '신호등에서 왼쪽으로 돌고 나서 약 200미터 직진하세요.'
WHERE id = 's_transport_A1_05';

UPDATE sentences SET
  ex1 = 'Go straight and then turn right.', ex1_ko = '직진한 다음 오른쪽으로 도세요.',
  ex2 = 'Go straight on and then turn right at the junction.', ex2_ko = '직진하다가 교차로에서 오른쪽으로 도세요.',
  ex3 = 'Keep going straight and then make a right turn at the corner.', ex3_ko = '계속 직진하다가 모퉁이에서 우회전하세요.',
  ex4 = 'Go straight past the school and then turn right at the roundabout.', ex4_ko = '학교를 지나 직진한 후 로터리에서 우회전하세요.',
  ex5 = 'Walk straight ahead for about five minutes and then turn right — you will see the station.', ex5_ko = '약 5분 직진한 후 오른쪽으로 돌면 역이 보일 거예요.'
WHERE id = 's_transport_A1_06';

UPDATE sentences SET
  ex1 = 'Excuse me, can you show me the way to the subway?', ex1_ko = '실례합니다, 지하철로 가는 길을 알려 주실 수 있나요?',
  ex2 = 'I am sorry to bother you, but could you direct me to the subway?', ex2_ko = '죄송한데, 지하철로 가는 방향을 알려 주실 수 있을까요?',
  ex3 = 'Excuse me, is the subway station nearby?', ex3_ko = '실례합니다, 지하철역이 근처에 있나요?',
  ex4 = 'Could you help me find the way to the subway entrance?', ex4_ko = '지하철 입구로 가는 길을 찾는 데 도움을 주실 수 있나요?',
  ex5 = 'I seem to be lost — could you show me how to get to the subway from here?', ex5_ko = '길을 잃은 것 같아요 — 여기서 지하철 가는 방법을 알려 주실 수 있나요?'
WHERE id = 's_transport_A1_07';

UPDATE sentences SET
  ex1 = 'I''d like a return ticket to Busan, please.', ex1_ko = '부산행 왕복 티켓 한 장 부탁드려요.',
  ex2 = 'Could I have a return ticket to Busan for tomorrow, please?', ex2_ko = '내일 부산행 왕복 티켓 한 장 주시겠어요?',
  ex3 = 'I would like to buy a return ticket to Busan — how much is it?', ex3_ko = '부산행 왕복 티켓을 사고 싶은데 얼마인가요?',
  ex4 = 'Is the return ticket to Busan available for this weekend?', ex4_ko = '이번 주말 부산행 왕복 티켓을 구할 수 있나요?',
  ex5 = 'Two return tickets to Busan on Friday evening, please.', ex5_ko = '금요일 저녁 부산행 왕복 티켓 두 장 부탁드려요.'
WHERE id = 's_transport_A2_01';

UPDATE sentences SET
  ex1 = 'How much is the fare to the airport?', ex1_ko = '공항까지 요금이 얼마인가요?',
  ex2 = 'Excuse me, can you tell me what the fare is to the airport?', ex2_ko = '실례합니다, 공항까지 요금이 얼마인지 알려 주실 수 있나요?',
  ex3 = 'Is the fare to the airport different for children?', ex3_ko = '공항까지 어린이 요금이 다른가요?',
  ex4 = 'What is the cheapest way to get to the airport, and how much is the fare?', ex4_ko = '공항에 가는 가장 저렴한 방법과 요금이 얼마인가요?',
  ex5 = 'The fare to the airport on the express train is quite reasonable.', ex5_ko = '급행 열차로 공항까지 가는 요금은 꽤 합리적이에요.'
WHERE id = 's_transport_A2_02';

UPDATE sentences SET
  ex1 = 'Do I need to transfer to get to Gangnam?', ex1_ko = '강남까지 가려면 환승해야 하나요?',
  ex2 = 'Is there a direct line to Gangnam, or do I need to transfer?', ex2_ko = '강남으로 가는 직행 노선이 있나요, 아니면 환승해야 하나요?',
  ex3 = 'How many times do I need to transfer to get to Gangnam?', ex3_ko = '강남까지 가려면 몇 번 환승해야 하나요?',
  ex4 = 'Which station should I transfer at to get to Gangnam?', ex4_ko = '강남에 가려면 어느 역에서 환승해야 하나요?',
  ex5 = 'You only need to transfer once — at City Hall — to get to Gangnam.', ex5_ko = '강남까지 가려면 시청에서 한 번만 환승하면 돼요.'
WHERE id = 's_transport_A2_03';

UPDATE sentences SET
  ex1 = 'Where do I transfer for the red line?', ex1_ko = '빨간 노선으로 갈아타려면 어디서 환승하나요?',
  ex2 = 'Which platform do I use to transfer to the red line?', ex2_ko = '빨간 노선으로 환승하려면 어느 승강장을 이용하나요?',
  ex3 = 'Could you tell me where to change for the red line?', ex3_ko = '빨간 노선으로 갈아타는 곳을 알려 주실 수 있나요?',
  ex4 = 'I need to get to the red line — where should I transfer?', ex4_ko = '빨간 노선으로 가야 하는데 어디서 환승해야 하나요?',
  ex5 = 'The transfer for the red line is at the next station — just follow the signs.', ex5_ko = '빨간 노선 환승은 다음 역에서 할 수 있어요 — 표지판을 따라가세요.'
WHERE id = 's_transport_A2_04';

UPDATE sentences SET
  ex1 = 'Is there a discount for students?', ex1_ko = '학생 할인이 있나요?',
  ex2 = 'Do you offer a student discount on monthly passes?', ex2_ko = '월간 정기권에 학생 할인을 제공하나요?',
  ex3 = 'I am a student — am I entitled to a reduced fare?', ex3_ko = '저는 학생인데 할인 요금을 받을 수 있나요?',
  ex4 = 'How much is the student discount on single fares?', ex4_ko = '편도 요금에서 학생 할인이 얼마인가요?',
  ex5 = 'You can get a student discount if you show your valid student card at the desk.', ex5_ko = '안내 데스크에서 유효한 학생증을 제시하면 학생 할인을 받을 수 있어요.'
WHERE id = 's_transport_A2_05';

UPDATE sentences SET
  ex1 = 'What time is the next train to Seoul?', ex1_ko = '서울행 다음 열차는 몇 시인가요?',
  ex2 = 'Could you check when the next train to Seoul departs?', ex2_ko = '서울행 다음 열차가 언제 출발하는지 확인해 주실 수 있나요?',
  ex3 = 'I have missed my train — what time is the next one to Seoul?', ex3_ko = '기차를 놓쳤는데 서울행 다음 열차는 몇 시인가요?',
  ex4 = 'The next train to Seoul leaves at quarter past three from platform two.', ex4_ko = '서울행 다음 열차는 3시 15분에 2번 승강장에서 출발해요.',
  ex5 = 'Is there still a train to Seoul after nine in the evening?', ex5_ko = '저녁 9시 이후에도 서울행 열차가 있나요?'
WHERE id = 's_transport_A2_06';

UPDATE sentences SET
  ex1 = 'Can I use this card to pay for the bus?', ex1_ko = '이 카드로 버스 요금을 낼 수 있나요?',
  ex2 = 'Does the bus accept contactless card payment?', ex2_ko = '버스에서 카드 비접촉 결제가 되나요?',
  ex3 = 'Is it possible to pay by card on the bus, or does it have to be cash?', ex3_ko = '버스에서 카드로 결제할 수 있나요, 아니면 현금만 가능한가요?',
  ex4 = 'I would like to pay by card — is that accepted on this service?', ex4_ko = '카드로 결제하고 싶은데 이 서비스에서 받나요?',
  ex5 = 'Most buses in the city now accept card payment, so you do not need cash.', ex5_ko = '도시의 대부분의 버스는 이제 카드 결제를 받기 때문에 현금이 필요하지 않아요.'
WHERE id = 's_transport_A2_07';

UPDATE sentences SET
  ex1 = 'I think I missed my stop — how do I get back?', ex1_ko = '정류장을 지나친 것 같은데 어떻게 돌아가나요?',
  ex2 = 'I got off one stop too early — can I board the next bus without paying again?', ex2_ko = '한 정거장 일찍 내렸는데 다시 요금을 내지 않고 다음 버스를 탈 수 있나요?',
  ex3 = 'I missed my stop and now I am in completely the wrong area — what should I do?', ex3_ko = '정류장을 지나쳐서 완전히 엉뚱한 곳에 있어요 — 어떻게 해야 하나요?',
  ex4 = 'I fell asleep on the train and missed my stop — is there a fast way to get back?', ex4_ko = '기차에서 잠들어서 내려야 할 곳을 지나쳤어요 — 빨리 돌아가는 방법이 있나요?',
  ex5 = 'If I miss my stop, I can simply wait for the next service back — it is not a big problem.', ex5_ko = '정류장을 지나치면 다음 역방향 서비스를 기다리면 돼요 — 큰 문제는 아니에요.'
WHERE id = 's_transport_B1_01';

UPDATE sentences SET
  ex1 = 'Could you take the main road instead of the highway? It might be quicker.', ex1_ko = '고속도로 대신 큰 도로로 가 주시겠어요? 더 빠를 수도 있어요.',
  ex2 = 'The highway is jammed — would you mind going via the main road?', ex2_ko = '고속도로가 막혀 있어요 — 큰 도로를 통해 가도 괜찮으세요?',
  ex3 = 'Please avoid the highway today — roadworks are causing long delays.', ex3_ko = '오늘은 고속도로를 피해 주세요 — 도로 공사로 인해 긴 지연이 발생하고 있어요.',
  ex4 = 'I would prefer to go by the main road if you do not mind — I find the highway quite stressful.', ex4_ko = '괜찮으시다면 큰 도로로 가고 싶어요 — 고속도로가 좀 부담스럽게 느껴져요.',
  ex5 = 'The scenic main road adds about ten minutes but is far more pleasant than the motorway.', ex5_ko = '경치 좋은 큰 도로는 약 10분이 더 걸리지만 고속도로보다 훨씬 쾌적해요.'
WHERE id = 's_transport_B1_02';

UPDATE sentences SET
  ex1 = 'The commute is really getting to me — I spend nearly two hours on the train every day.', ex1_ko = '통근이 정말 힘들어져요 — 매일 기차에서 거의 두 시간을 보내요.',
  ex2 = 'I have been commuting for five years and the journey never gets easier.', ex2_ko = '5년째 통근하고 있는데 여정이 전혀 수월해지지 않아요.',
  ex3 = 'My commute involves two buses and a fifteen-minute walk, which is exhausting in bad weather.', ex3_ko = '제 통근은 버스 두 번과 15분 도보를 포함하는데, 날씨가 나쁠 때는 매우 힘들어요.',
  ex4 = 'Working remotely twice a week has made my commute much more manageable.', ex4_ko = '주 2일 원격 근무 덕분에 통근이 훨씬 더 감당하기 쉬워졌어요.',
  ex5 = 'Long commutes have been linked to higher levels of stress and lower job satisfaction.', ex5_ko = '긴 통근은 더 높은 스트레스 수준과 낮은 직업 만족도와 관련이 있어요.'
WHERE id = 's_transport_B1_03';

UPDATE sentences SET
  ex1 = 'I usually carpool with two colleagues to save on fuel costs.', ex1_ko = '연료 비용을 절약하기 위해 보통 동료 두 명과 카풀해요.',
  ex2 = 'We set up a carpool rota so that each of us drives once a week.', ex2_ko = '각자 주 1회 운전하도록 카풀 순번을 만들었어요.',
  ex3 = 'Carpooling with neighbours has saved me a considerable amount on commuting costs.', ex3_ko = '이웃과 카풀해서 통근 비용을 상당히 절약했어요.',
  ex4 = 'I joined a carpooling app and now share my daily commute with three others.', ex4_ko = '카풀 앱에 가입해서 이제 세 명과 매일 통근을 함께해요.',
  ex5 = 'Carpooling not only reduces costs but also helps cut the number of vehicles on the road.', ex5_ko = '카풀은 비용을 줄일 뿐만 아니라 도로 위 차량 수를 줄이는 데도 도움이 돼요.'
WHERE id = 's_transport_B1_04';

UPDATE sentences SET
  ex1 = 'There are roadworks on the bridge, so we had to take a detour through the town.', ex1_ko = '다리에 도로 공사가 있어서 마을을 통해 우회해야 했어요.',
  ex2 = 'The road was closed for repairs, which forced us onto a long detour.', ex2_ko = '수리를 위해 도로가 폐쇄되어 긴 우회로를 이용해야 했어요.',
  ex3 = 'The detour added nearly half an hour to our journey — the roadworks are a real inconvenience.', ex3_ko = '우회로 때문에 여정에 거의 30분이 추가되었어요 — 도로 공사가 정말 불편해요.',
  ex4 = 'Roadworks on three separate routes meant we could not avoid a lengthy detour.', ex4_ko = '세 개의 별도 노선에 도로 공사가 있어서 긴 우회로를 피할 수 없었어요.',
  ex5 = 'Signs directing us through the roadworks detour were poorly placed and easy to miss.', ex5_ko = '도로 공사 우회로를 안내하는 표지판이 잘못 놓여 있어서 놓치기 쉬웠어요.'
WHERE id = 's_transport_B1_05';

UPDATE sentences SET
  ex1 = 'Is there a more direct route, or do we have to go through the tunnel?', ex1_ko = '더 직접적인 경로가 있나요, 아니면 터널을 통과해야 하나요?',
  ex2 = 'Can we take a more direct route to avoid the traffic in the centre?', ex2_ko = '중심부 교통을 피하기 위해 더 직접적인 경로를 이용할 수 있나요?',
  ex3 = 'Is the direct route open at this time of night, or is it closed?', ex3_ko = '이 밤 시간에 직행 경로가 열려 있나요, 아니면 폐쇄되어 있나요?',
  ex4 = 'I prefer to take the direct route even if the road is busier.', ex4_ko = '도로가 더 붐비더라도 직행 경로로 가는 것을 선호해요.',
  ex5 = 'The direct motorway route is faster, but the scenic road through the valley is much more enjoyable.', ex5_ko = '직행 고속도로 경로가 더 빠르지만, 계곡을 통과하는 경치 좋은 도로가 훨씬 더 즐거워요.'
WHERE id = 's_transport_B1_06';

UPDATE sentences SET
  ex1 = 'Watch out — there''s a speed camera just after that bend.', ex1_ko = '조심하세요 — 저 커브 바로 다음에 속도 카메라가 있어요.',
  ex2 = 'I slowed down because I noticed a speed camera ahead.', ex2_ko = '앞에 속도 카메라가 있는 것을 발견해서 속도를 줄였어요.',
  ex3 = 'The speed camera on this stretch of road has caught a lot of drivers over the limit.', ex3_ko = '이 도로 구간의 속도 카메라가 제한 속도를 초과하는 많은 운전자를 단속했어요.',
  ex4 = 'Always drive within the speed limit — there are cameras throughout this area.', ex4_ko = '항상 제한 속도 내에서 운전하세요 — 이 지역 전체에 카메라가 있어요.',
  ex5 = 'The new average-speed camera system has noticeably reduced speeding on this road.', ex5_ko = '새로운 구간 속도 카메라 시스템이 이 도로에서의 과속을 눈에 띄게 줄였어요.'
WHERE id = 's_transport_B1_07';

UPDATE sentences SET
  ex1 = 'The congestion on this corridor has reached a critical point and something has to be done.', ex1_ko = '이 회랑의 혼잡이 임계점에 도달했으며 무언가 조치가 취해져야 해요.',
  ex2 = 'Congestion on the main arterial roads has worsened significantly since the new development opened.', ex2_ko = '새 개발지가 개통된 이후 주요 간선도로의 혼잡이 크게 악화되었어요.',
  ex3 = 'The transport authority is under pressure to address the growing congestion on the northern bypass.', ex3_ko = '교통 당국이 북쪽 우회도로의 증가하는 혼잡 문제를 해결하라는 압박을 받고 있어요.',
  ex4 = 'Congestion in the port area has led to serious delays in the supply chain.', ex4_ko = '항구 지역의 혼잡이 공급망에 심각한 지연을 초래했어요.',
  ex5 = 'Without investment in public transport, congestion on the main roads will only get worse.', ex5_ko = '대중교통 투자 없이는 주요 도로의 혼잡이 더욱 악화될 거예요.'
WHERE id = 's_transport_B2_01';

UPDATE sentences SET
  ex1 = 'The delay was caused by an overhead line failure, which disrupted services across the entire network.', ex1_ko = '가공선 고장으로 인해 지연이 발생했으며, 이는 전체 네트워크의 서비스를 혼란에 빠뜨렸어요.',
  ex2 = 'An overhead line failure near the central station brought the entire suburban rail network to a halt.', ex2_ko = '중앙역 근처의 가공선 고장으로 교외 철도 네트워크 전체가 멈췄어요.',
  ex3 = 'Passengers were left stranded for over two hours following the overhead line failure.', ex3_ko = '승객들은 가공선 고장으로 두 시간 이상 발이 묶였어요.',
  ex4 = 'The overhead line failure was the third such incident this month, raising serious safety concerns.', ex4_ko = '이번 달 세 번째 가공선 고장 사건으로 심각한 안전 우려가 제기되었어요.',
  ex5 = 'Engineers worked through the night to repair the overhead line failure before the morning rush.', ex5_ko = '엔지니어들이 아침 러시아워 전에 가공선 고장을 수리하기 위해 밤새 작업했어요.'
WHERE id = 's_transport_B2_02';

UPDATE sentences SET
  ex1 = 'Despite the disruption, alternative shuttle services were put in place within the hour.', ex1_ko = '혼란에도 불구하고 1시간 이내에 대체 셔틀 서비스가 마련되었어요.',
  ex2 = 'The operator responded to the disruption quickly by deploying replacement bus services.', ex2_ko = '운영사가 대체 버스 서비스를 배치해 혼란에 빠르게 대응했어요.',
  ex3 = 'Passengers affected by the disruption were offered full refunds or alternative travel options.', ex3_ko = '혼란의 영향을 받은 승객들에게 전액 환불 또는 대체 여행 옵션이 제공되었어요.',
  ex4 = 'The disruption to services was minimised thanks to a well-rehearsed contingency plan.', ex4_ko = '잘 훈련된 비상 계획 덕분에 서비스 혼란이 최소화되었어요.',
  ex5 = 'Despite the severe disruption caused by flooding, the last train of the day still managed to run.', ex5_ko = '홍수로 인한 심각한 혼란에도 불구하고 그날의 마지막 열차는 여전히 운행할 수 있었어요.'
WHERE id = 's_transport_B2_03';

UPDATE sentences SET
  ex1 = 'The introduction of congestion charges has significantly reduced traffic in the city centre.', ex1_ko = '혼잡 통행료 도입으로 시내 교통량이 크게 줄었어요.',
  ex2 = 'Since the congestion charge was introduced, air quality in the city centre has improved markedly.', ex2_ko = '혼잡 통행료가 도입된 이후 시내 대기 질이 눈에 띄게 개선되었어요.',
  ex3 = 'The proposed expansion of the congestion charge zone has proved highly controversial.', ex3_ko = '혼잡 통행료 구역의 제안된 확장은 매우 논란이 많은 것으로 판명되었어요.',
  ex4 = 'Revenue from congestion charges has been reinvested in new cycling and bus infrastructure.', ex4_ko = '혼잡 통행료 수입이 새로운 자전거 및 버스 인프라에 재투자되었어요.',
  ex5 = 'Critics of the congestion charge argue that it places an unfair burden on lower-income workers.', ex5_ko = '혼잡 통행료 비판론자들은 그것이 저소득 근로자에게 불공평한 부담을 준다고 주장해요.'
WHERE id = 's_transport_B2_04';

UPDATE sentences SET
  ex1 = 'I missed my connecting flight because the first leg arrived over an hour behind schedule.', ex1_ko = '첫 번째 구간이 예정보다 한 시간 이상 늦게 도착해서 연결 항공편을 놓쳤어요.',
  ex2 = 'My connecting flight had already departed by the time my delayed train arrived at the airport.', ex2_ko = '지연된 기차가 공항에 도착했을 때 이미 연결 항공편은 출발한 뒤였어요.',
  ex3 = 'Always allow at least ninety minutes between connections to avoid missing a flight.', ex3_ko = '항공편을 놓치지 않으려면 환승 사이에 최소 90분을 여유로 두세요.',
  ex4 = 'The airline rebooked me on the next available flight after I missed my connection.', ex4_ko = '연결 편을 놓친 후 항공사가 다음 가능한 항공편으로 재예약해 주었어요.',
  ex5 = 'Tight connections are always a gamble — I now only book flights with longer layovers.', ex5_ko = '짧은 환승 시간은 항상 도박이에요 — 이제는 더 긴 경유 시간의 항공편만 예약해요.'
WHERE id = 's_transport_B2_05';

UPDATE sentences SET
  ex1 = 'The infrastructure upgrade will require significant capital investment spread over five years.', ex1_ko = '인프라 업그레이드는 5년에 걸쳐 분산되는 상당한 자본 투자가 필요해요.',
  ex2 = 'The rail infrastructure upgrade will deliver faster, more reliable services for millions of passengers.', ex2_ko = '철도 인프라 업그레이드는 수백만 승객에게 더 빠르고 안정적인 서비스를 제공할 거예요.',
  ex3 = 'Without the infrastructure upgrade, the network cannot handle the projected growth in passenger numbers.', ex3_ko = '인프라 업그레이드 없이는 네트워크가 예상되는 승객 수 증가를 처리할 수 없어요.',
  ex4 = 'The infrastructure upgrade includes new signalling, additional platforms, and faster rolling stock.', ex4_ko = '인프라 업그레이드에는 새로운 신호 체계, 추가 승강장, 더 빠른 차량이 포함돼요.',
  ex5 = 'Funding for the infrastructure upgrade was finally secured after years of negotiation.', ex5_ko = '수년간의 협상 끝에 인프라 업그레이드를 위한 자금이 마침내 확보되었어요.'
WHERE id = 's_transport_B2_06';

UPDATE sentences SET
  ex1 = 'Passengers are advised to allow extra travel time due to planned engineering works this weekend.', ex1_ko = '이번 주말 계획된 공사 작업으로 인해 승객들은 여유 있는 이동 시간을 두도록 안내 드려요.',
  ex2 = 'Due to planned engineering works, the service will terminate at the city boundary and passengers should use the replacement bus.', ex2_ko = '계획된 공사 작업으로 인해 서비스가 도시 경계에서 종착되니 승객들은 대체 버스를 이용하시기 바라요.',
  ex3 = 'Engineering works will affect services between Saturday night and Monday morning — please plan your journey in advance.', ex3_ko = '공사 작업이 토요일 밤부터 월요일 아침까지 서비스에 영향을 미칠 예정이니 미리 여정을 계획해 주세요.',
  ex4 = 'The planned engineering works are essential to improve long-term reliability on this section of the line.', ex4_ko = '계획된 공사 작업은 이 노선 구간의 장기 신뢰성을 향상시키기 위해 필수적이에요.',
  ex5 = 'Advance notice of engineering works gives passengers the opportunity to make alternative arrangements.', ex5_ko = '공사 작업의 사전 통지는 승객들이 대안을 마련할 기회를 제공해요.'
WHERE id = 's_transport_B2_07';

UPDATE sentences SET
  ex1 = 'A shift toward sustainable transport modes requires not only infrastructure investment but also a fundamental change in commuter behaviour.', ex1_ko = '지속 가능한 교통 수단으로의 전환은 인프라 투자뿐만 아니라 통근자 행동의 근본적인 변화도 필요해요.',
  ex2 = 'Sustainable transport planning must balance environmental goals with the practical needs of a growing urban population.', ex2_ko = '지속 가능한 교통 계획은 환경 목표와 성장하는 도시 인구의 실용적인 필요 사이의 균형을 맞춰야 해요.',
  ex3 = 'The transition to sustainable transport modes will take decades and requires consistent political will.', ex3_ko = '지속 가능한 교통 수단으로의 전환은 수십 년이 걸리며 일관된 정치적 의지가 필요해요.',
  ex4 = 'Sustainable transport is not merely an environmental issue — it is also central to public health and social equity.', ex4_ko = '지속 가능한 교통은 환경적 문제만이 아니에요 — 그것은 공중 보건과 사회적 형평성의 핵심이기도 해요.',
  ex5 = 'Investing in sustainable transport infrastructure today will yield significant social and economic dividends for future generations.', ex5_ko = '오늘 지속 가능한 교통 인프라에 투자하면 미래 세대에게 상당한 사회적, 경제적 이익을 가져다줄 거예요.'
WHERE id = 's_transport_C1_01';

UPDATE sentences SET
  ex1 = 'Transit-oriented development has proven effective in cities that have aligned planning decisions with public transport corridors.', ex1_ko = '대중교통 중심 개발은 계획 결정을 대중교통 회랑과 일치시킨 도시들에서 효과적인 것으로 입증되었어요.',
  ex2 = 'Cities that embraced transit-oriented development early have seen higher public transport ridership and lower car dependency.', ex2_ko = '대중교통 중심 개발을 일찍 도입한 도시들은 더 높은 대중교통 승객 수와 낮은 자가용 의존도를 보였어요.',
  ex3 = 'Transit-oriented development encourages mixed-use, walkable neighbourhoods centred around rail and bus hubs.', ex3_ko = '대중교통 중심 개발은 철도 및 버스 허브를 중심으로 한 복합 용도의 보행 친화적 주거지를 장려해요.',
  ex4 = 'The success of transit-oriented development depends heavily on the quality and frequency of the public transport services it is built around.', ex4_ko = '대중교통 중심 개발의 성공은 그 주변에 구축된 대중교통 서비스의 품질과 빈도에 크게 달려 있어요.',
  ex5 = 'Critics of transit-oriented development argue that it can drive up property prices and displace lower-income residents.', ex5_ko = '대중교통 중심 개발 비판론자들은 그것이 부동산 가격을 올리고 저소득 거주자들을 내쫓을 수 있다고 주장해요.'
WHERE id = 's_transport_C1_02';

UPDATE sentences SET
  ex1 = 'The challenge lies in achieving modal shift without disproportionately burdening lower-income households.', ex1_ko = '과제는 저소득 가정에 불균형적인 부담을 주지 않으면서 수단 전환을 달성하는 데 있어요.',
  ex2 = 'Modal shift policies must be accompanied by affordable public transport to avoid penalising those who depend on their cars.', ex2_ko = '수단 전환 정책은 자가용에 의존하는 사람들을 불이익 주지 않기 위해 저렴한 대중교통과 함께 이루어져야 해요.',
  ex3 = 'Achieving meaningful modal shift requires pricing incentives, infrastructure investment, and genuine behavioural change.', ex3_ko = '의미 있는 수단 전환을 달성하려면 가격 인센티브, 인프라 투자, 그리고 진정한 행동 변화가 필요해요.',
  ex4 = 'The government''s modal shift targets are ambitious but achievable if sustained investment is maintained over the next decade.', ex4_ko = '정부의 수단 전환 목표는 야심차지만, 향후 10년간 지속적인 투자가 유지된다면 달성 가능해요.',
  ex5 = 'Modal shift away from aviation to high-speed rail is seen as one of the most effective short-haul decarbonization strategies.', ex5_ko = '항공에서 고속 철도로의 수단 전환은 단거리 탈탄소화 전략 중 가장 효과적인 방법 중 하나로 여겨져요.'
WHERE id = 's_transport_C1_03';

UPDATE sentences SET
  ex1 = 'Electrification of the rail network is central to the government''s decarbonization strategy.', ex1_ko = '철도망 전철화는 정부의 탈탄소화 전략의 핵심이에요.',
  ex2 = 'Full electrification of the rail network will eliminate diesel traction and significantly cut emissions.', ex2_ko = '철도망의 완전 전철화는 디젤 견인을 없애고 배출량을 크게 줄일 거예요.',
  ex3 = 'The electrification programme faces delays due to rising costs and supply chain issues.', ex3_ko = '전철화 프로그램이 비용 상승과 공급망 문제로 인해 지연에 직면해 있어요.',
  ex4 = 'Rail electrification makes economic sense in high-density corridors where passenger volumes justify the capital outlay.', ex4_ko = '철도 전철화는 승객 수가 자본 지출을 정당화하는 고밀도 회랑에서 경제적으로 타당해요.',
  ex5 = 'Battery and hydrogen trains are being considered as alternatives to full electrification in rural areas.', ex5_ko = '농촌 지역의 완전 전철화에 대한 대안으로 배터리 및 수소 열차가 검토되고 있어요.'
WHERE id = 's_transport_C1_04';

UPDATE sentences SET
  ex1 = 'Autonomous vehicles hold considerable promise, but regulatory frameworks have yet to keep pace with technological development.', ex1_ko = '자율 주행 차량은 상당한 가능성을 가지고 있지만, 규제 체계는 아직 기술 발전을 따라가지 못하고 있어요.',
  ex2 = 'Widespread deployment of autonomous vehicles will require not only technological maturity but also public acceptance.', ex2_ko = '자율 주행 차량의 광범위한 배치는 기술적 성숙뿐만 아니라 대중의 수용도 필요해요.',
  ex3 = 'Autonomous vehicles could dramatically reduce road accidents caused by human error.', ex3_ko = '자율 주행 차량은 인간의 실수로 인한 교통 사고를 크게 줄일 수 있어요.',
  ex4 = 'The insurance industry is struggling to adapt its models to the unique liability questions posed by autonomous vehicles.', ex4_ko = '보험 업계가 자율 주행 차량이 제기하는 독특한 책임 문제에 맞게 모델을 적응시키는 데 어려움을 겪고 있어요.',
  ex5 = 'Public scepticism about autonomous vehicles remains high despite evidence of their potential safety benefits.', ex5_ko = '잠재적인 안전 혜택에 관한 증거에도 불구하고 자율 주행 차량에 대한 대중의 회의론은 여전히 높아요.'
WHERE id = 's_transport_C1_05';

UPDATE sentences SET
  ex1 = 'Improving last-mile connectivity is critical if public transport is to compete effectively with the private car.', ex1_ko = '대중교통이 자가용과 효과적으로 경쟁하려면 라스트마일 연결성을 개선하는 것이 매우 중요해요.',
  ex2 = 'The biggest barrier to using public transport is often the poor last-mile connectivity at the destination end.', ex2_ko = '대중교통 이용의 가장 큰 장벽은 종종 목적지 쪽의 열악한 라스트마일 연결성이에요.',
  ex3 = 'E-bikes and shared scooters have emerged as effective tools for solving last-mile connectivity challenges.', ex3_ko = '전기 자전거와 공유 킥보드가 라스트마일 연결성 문제를 해결하는 효과적인 도구로 부상했어요.',
  ex4 = 'Investment in last-mile connectivity yields the highest returns in areas where the core public transport network is already strong.', ex4_ko = '라스트마일 연결성에 대한 투자는 핵심 대중교통 네트워크가 이미 강한 지역에서 가장 높은 수익을 거둬요.',
  ex5 = 'Transport planning must address last-mile connectivity alongside the main network if it is to change travel behaviour meaningfully.', ex5_ko = '교통 계획은 여행 행동을 의미 있게 변화시키려면 주요 네트워크와 함께 라스트마일 연결성을 다루어야 해요.'
WHERE id = 's_transport_C1_06';

UPDATE sentences SET
  ex1 = 'Ridesharing platforms have disrupted traditional taxi markets, compelling regulators to revisit licensing frameworks.', ex1_ko = '라이드셰어링 플랫폼이 전통적인 택시 시장을 혼란에 빠뜨려 규제 기관들이 허가 체계를 재검토하게 만들었어요.',
  ex2 = 'The rapid growth of ridesharing has forced local governments to develop new regulatory approaches for gig-economy transport.', ex2_ko = '라이드셰어링의 급격한 성장으로 지방 정부들이 긱 이코노미 교통을 위한 새로운 규제 방식을 개발해야 했어요.',
  ex3 = 'Ridesharing companies argue that they offer greater flexibility and lower prices than traditional taxis.', ex3_ko = '라이드셰어링 업체들은 기존 택시보다 더 큰 유연성과 낮은 가격을 제공한다고 주장해요.',
  ex4 = 'The labour rights of ridesharing drivers remain a contentious issue in many jurisdictions.', ex4_ko = '라이드셰어링 기사들의 노동권은 많은 법적 관할 구역에서 여전히 논쟁적인 문제예요.',
  ex5 = 'Evidence suggests that ridesharing has increased overall vehicle kilometres travelled rather than reducing congestion.', ex5_ko = '증거에 따르면 라이드셰어링이 혼잡을 줄이기보다 오히려 전체 차량 이동 킬로미터를 증가시켰어요.'
WHERE id = 's_transport_C1_07';

UPDATE sentences SET
  ex1 = 'The externalities associated with private car use — including congestion, pollution, and noise — are rarely captured in market prices, necessitating corrective policy intervention.', ex1_ko = '혼잡, 오염, 소음을 포함한 자가용 사용과 관련된 외부성은 시장 가격에 거의 반영되지 않아, 수정적 정책 개입이 필요해요.',
  ex2 = 'Failing to internalise the externalities of road transport results in market failure and chronic underinvestment in public alternatives.', ex2_ko = '도로 교통의 외부성을 내부화하지 못하면 시장 실패와 대안적 공공 교통에 대한 만성적인 과소 투자가 발생해요.',
  ex3 = 'Transport economists have long argued that the true social cost of car travel significantly exceeds the price paid by individual drivers.', ex3_ko = '교통 경제학자들은 자동차 여행의 진정한 사회적 비용이 개별 운전자가 지불하는 가격을 크게 초과한다고 오랫동안 주장해왔어요.',
  ex4 = 'A carbon tax on transport fuels is one mechanism for internalising the environmental externality of greenhouse gas emissions.', ex4_ko = '교통 연료에 대한 탄소세는 온실 가스 배출의 환경적 외부성을 내부화하는 메커니즘 중 하나예요.',
  ex5 = 'The failure to price transport externalities accurately skews individual travel choices in favour of the private car over greener alternatives.', ex5_ko = '교통 외부성을 정확하게 가격 책정하지 않으면 개인의 이동 선택이 친환경적 대안보다 자가용을 선호하는 방향으로 왜곡돼요.'
WHERE id = 's_transport_C2_01';

UPDATE sentences SET
  ex1 = 'Decarbonizing aviation at scale will require breakthroughs in propulsion technology, given that the energy density of current battery systems remains insufficient for long-haul flight.', ex1_ko = '현재 배터리 시스템의 에너지 밀도가 장거리 비행에 여전히 부족하다는 점을 감안할 때, 항공의 대규모 탈탄소화는 추진 기술의 혁신이 필요해요.',
  ex2 = 'Sustainable aviation fuels offer a near-term pathway to reducing emissions, but their cost and scalability remain significant obstacles.', ex2_ko = '지속 가능한 항공 연료는 배출량을 줄이는 단기적인 경로를 제공하지만, 그 비용과 확장성은 여전히 중요한 장애물이에요.',
  ex3 = 'The aviation industry''s decarbonization commitments have been criticised as insufficient given the scale of emissions growth projected for the sector.', ex3_ko = '항공 산업의 탈탄소화 약속은 해당 부문의 예상 배출량 증가 규모를 감안할 때 부족하다는 비판을 받아왔어요.',
  ex4 = 'Hydrogen propulsion for short-haul aircraft is being actively researched, though commercial deployment remains years away.', ex4_ko = '단거리 항공기용 수소 추진이 활발히 연구되고 있지만, 상업적 배치는 아직 수년 더 걸릴 거예요.',
  ex5 = 'A meaningful reduction in aviation emissions will require demand management alongside technological innovation.', ex5_ko = '항공 배출량의 의미 있는 감소는 기술 혁신과 함께 수요 관리가 필요해요.'
WHERE id = 's_transport_C2_02';

UPDATE sentences SET
  ex1 = 'The proliferation of micromobility services demands a rethinking of curbside management and urban streetscape design.', ex1_ko = '마이크로 모빌리티 서비스의 확산은 도로변 관리와 도시 가로 경관 설계에 대한 재고를 요구해요.',
  ex2 = 'Micromobility has the potential to replace a significant share of short car trips, but only if supported by adequate infrastructure.', ex2_ko = '마이크로 모빌리티는 적절한 인프라의 지원이 있을 때에만 상당한 비율의 단거리 자동차 이동을 대체할 잠재력이 있어요.',
  ex3 = 'The unregulated proliferation of dockless scooters has created hazards for pedestrians in many city centres.', ex3_ko = '규제 없는 도크리스 킥보드의 확산이 많은 도심에서 보행자에게 위험을 초래했어요.',
  ex4 = 'Cities that have integrated micromobility into their broader transport planning have seen the most successful outcomes.', ex4_ko = '마이크로 모빌리티를 더 넓은 교통 계획에 통합한 도시들이 가장 성공적인 결과를 보였어요.',
  ex5 = 'Micromobility regulation must balance innovation and safety while ensuring equitable access for all residents.', ex5_ko = '마이크로 모빌리티 규제는 모든 주민의 공평한 접근을 보장하면서 혁신과 안전 사이의 균형을 맞춰야 해요.'
WHERE id = 's_transport_C2_03';

UPDATE sentences SET
  ex1 = 'Realizing the potential of hyperloop technology hinges on resolving both the engineering and the regulatory challenges that currently impede deployment.', ex1_ko = '하이퍼루프 기술의 잠재력을 실현하는 것은 현재 배치를 방해하는 공학적 및 규제적 과제를 모두 해결하는 데 달려 있어요.',
  ex2 = 'Even if the engineering challenges of hyperloop are overcome, public acceptance and funding remain formidable barriers.', ex2_ko = '하이퍼루프의 공학적 과제가 극복되더라도, 대중의 수용과 자금 조달은 여전히 만만치 않은 장벽이에요.',
  ex3 = 'The hyperloop concept promises to revolutionise intercity travel, but sceptics question whether it can ever be commercially viable.', ex3_ko = '하이퍼루프 개념은 도시 간 이동을 혁신할 것을 약속하지만, 회의론자들은 그것이 상업적으로 실행 가능한지에 의문을 제기해요.',
  ex4 = 'A number of governments have signed agreements to facilitate hyperloop corridor feasibility studies.', ex4_ko = '여러 정부가 하이퍼루프 회랑 타당성 연구를 촉진하기 위한 협약에 서명했어요.',
  ex5 = 'The case for hyperloop is strongest in dense, linear corridors where air travel is currently dominant and rail is impractical.', ex5_ko = '하이퍼루프의 경우는 현재 항공 이동이 지배적이고 철도가 비실용적인 조밀하고 선형적인 회랑에서 가장 강해요.'
WHERE id = 's_transport_C2_04';

UPDATE sentences SET
  ex1 = 'Telematics data, when coupled with geospatial analysis, enables transport authorities to allocate resources with unprecedented precision.', ex1_ko = '원격 측정 데이터는 공간 분석과 결합될 때 교통 당국이 전례 없는 정밀도로 자원을 배분할 수 있게 해요.',
  ex2 = 'Combining telematics with geospatial analysis allows operators to identify underserved areas and optimise route coverage.', ex2_ko = '원격 측정과 공간 분석을 결합하면 운영자가 서비스가 부족한 지역을 파악하고 노선 커버리지를 최적화할 수 있어요.',
  ex3 = 'The transport authority uses telematics and geospatial analysis to predict and prevent congestion before it develops.', ex3_ko = '교통 당국은 원격 측정과 공간 분석을 이용해 혼잡이 발생하기 전에 예측하고 방지해요.',
  ex4 = 'Geospatial analysis of passenger flow data revealed significant gaps in the overnight bus network.', ex4_ko = '승객 흐름 데이터의 공간 분석에서 심야 버스 네트워크의 상당한 격차가 드러났어요.',
  ex5 = 'The integration of telematics and geospatial data has transformed evidence-based decision-making in public transport management.', ex5_ko = '원격 측정 및 공간 데이터의 통합이 대중교통 관리에서 근거 기반 의사 결정을 변화시켰어요.'
WHERE id = 's_transport_C2_05';

UPDATE sentences SET
  ex1 = 'Transport poverty, often overlooked in urban policy discourse, disproportionately affects peripheral communities with limited access to employment and services.', ex1_ko = '도시 정책 담론에서 종종 간과되는 교통 빈곤은 고용과 서비스에 대한 접근이 제한된 주변 지역 사회에 불균형적으로 영향을 미쳐요.',
  ex2 = 'Addressing transport poverty requires a combination of subsidised fares, improved service frequency, and better connectivity in underserved areas.', ex2_ko = '교통 빈곤을 해결하려면 보조금 지원 요금, 개선된 서비스 빈도, 서비스 부족 지역의 더 나은 연결성의 조합이 필요해요.',
  ex3 = 'Transport poverty is not limited to rural areas — many deprived urban neighbourhoods also suffer from inadequate public transport.', ex3_ko = '교통 빈곤은 농촌 지역에만 국한되지 않아요 — 많은 열악한 도시 주거지도 불충분한 대중교통으로 고통받아요.',
  ex4 = 'Research consistently links transport poverty to worse health outcomes, reduced employment opportunities, and social isolation.', ex4_ko = '연구에 따르면 교통 빈곤은 더 나쁜 건강 결과, 감소된 고용 기회, 사회적 고립과 지속적으로 연결되어 있어요.',
  ex5 = 'A national transport poverty strategy would require coordinated action across housing, employment, and transport policy.', ex5_ko = '국가 교통 빈곤 전략은 주택, 고용, 교통 정책 전반에 걸친 조정된 행동이 필요할 거예요.'
WHERE id = 's_transport_C2_06';

UPDATE sentences SET
  ex1 = 'A comprehensive Mobility as a Service ecosystem presupposes interoperability across competing platforms, a condition that market forces alone are unlikely to deliver without regulatory mandates.', ex1_ko = '포괄적인 서비스로서의 모빌리티 생태계는 경쟁하는 플랫폼 간의 상호 운용성을 전제로 하는데, 이는 규제 의무 없이 시장 원리만으로는 달성하기 어려운 조건이에요.',
  ex2 = 'The vision of Mobility as a Service, in which a single app handles all transport needs, remains largely unrealised in most cities.', ex2_ko = '하나의 앱이 모든 교통 필요를 처리하는 서비스로서의 모빌리티 비전은 대부분의 도시에서 아직 대부분 실현되지 않았어요.',
  ex3 = 'For Mobility as a Service to succeed, transport providers must agree to share data in a standardised, open format.', ex3_ko = '서비스로서의 모빌리티가 성공하려면, 교통 서비스 제공자들이 표준화된 개방적인 형식으로 데이터를 공유하는 데 동의해야 해요.',
  ex4 = 'Mobility as a Service has the potential to reduce car ownership, particularly among younger urban residents who already rely heavily on apps.', ex4_ko = '서비스로서의 모빌리티는 특히 앱에 이미 크게 의존하는 젊은 도시 거주자들 사이에서 자가용 소유를 줄일 잠재력이 있어요.',
  ex5 = 'Critics argue that Mobility as a Service may entrench the market power of major technology platforms rather than genuinely improving transport equity.', ex5_ko = '비판론자들은 서비스로서의 모빌리티가 교통 형평성을 진정으로 개선하기보다 주요 기술 플랫폼의 시장 지배력을 강화할 수 있다고 주장해요.'
WHERE id = 's_transport_C2_07';

