  ex3 = 'Is Wi-Fi included in the room price?', ex3_ko = '객실 요금에 와이파이가 포함되어 있나요?',
  ex4 = 'Is parking included in the hotel rate?', ex4_ko = '호텔 요금에 주차가 포함되어 있나요?',
