UPDATE sentences SET
  ex1 = 'It is very cold today, isn''t it?', ex1_ko = '오늘 매우 춥죠?',
  ex2 = 'It is very hot today, isn''t it?', ex2_ko = '오늘 매우 덥죠?',
  ex3 = 'It is very windy today, isn''t it?', ex3_ko = '오늘 바람이 매우 강하죠?',
  ex4 = 'It is very humid today, isn''t it?', ex4_ko = '오늘 매우 습하죠?',
  ex5 = 'It is very dark outside today, isn''t it?', ex5_ko = '오늘 밖이 매우 어둡죠?'
WHERE id = 's_weather_A1_07';

UPDATE sentences SET
  ex1 = 'The weather is really nice today, don''t you think?', ex1_ko = '오늘 날씨가 정말 좋죠, 그렇게 생각하지 않으세요?',
  ex2 = 'The coffee is really strong today, don''t you think?', ex2_ko = '오늘 커피가 정말 진하죠, 그렇게 생각하지 않으세요?',
  ex3 = 'The park is really beautiful in autumn, don''t you think?', ex3_ko = '가을에 공원이 정말 아름답죠, 그렇게 생각하지 않으세요?',
  ex4 = 'The city is really busy during the holidays, don''t you think?', ex4_ko = '휴일 동안 도시가 정말 바쁘죠, 그렇게 생각하지 않으세요?',
  ex5 = 'The air is really fresh after the rain, don''t you think?', ex5_ko = '비가 온 후 공기가 정말 맑죠, 그렇게 생각하지 않으세요?'
WHERE id = 's_weather_A2_01';

UPDATE sentences SET
  ex1 = 'It''s getting colder these days.', ex1_ko = '요즘 날씨가 점점 추워지고 있어요.',
