  ex2 = 'The forecast says it will be sunny all weekend.', ex2_ko = '예보에서 주말 내내 맑을 것이라고 해요.',
  ex3 = 'The forecast says it will snow heavily tonight.', ex3_ko = '예보에서 오늘 밤 눈이 많이 올 것이라고 해요.',
  ex4 = 'The forecast says temperatures will drop below zero by midnight.', ex4_ko = '예보에서 자정까지 기온이 영하로 떨어질 것이라고 해요.',
