UPDATE sentences SET
  ex1 = 'It was so foggy this morning that I could barely see.', ex1_ko = '오늘 아침 안개가 너무 짙어서 거의 앞을 볼 수 없었어요.',
  ex2 = 'It was so dark this morning that I thought it was still night.', ex2_ko = '오늘 아침이 너무 어두워서 아직 밤인 줄 알았어요.',
  ex3 = 'It was so icy this morning that I could barely walk to the bus stop.', ex3_ko = '오늘 아침 얼음이 너무 많아서 버스 정류장까지 걷기가 거의 어려웠어요.',
  ex4 = 'It was so windy this morning that I could barely open the car door.', ex4_ko = '오늘 아침 바람이 너무 강해서 차 문을 열기가 거의 어려웠어요.',
  ex5 = 'It was so sunny this morning that I had to wear my sunglasses just to drive.', ex5_ko = '오늘 아침 햇빛이 너무 강해서 운전하려면 선글라스를 써야 했어요.'
