UPDATE sentences SET
  ex1 = 'I prefer sunny weather to rainy weather.', ex1_ko = '저는 비 오는 날씨보다 맑은 날씨를 더 좋아해요.',
  ex2 = 'I prefer warm weather to cold weather.', ex2_ko = '저는 추운 날씨보다 따뜻한 날씨를 더 좋아해요.',
  ex3 = 'I prefer dry heat to humid heat.', ex3_ko = '저는 습한 더위보다 건조한 더위를 더 좋아해요.',
  ex4 = 'I prefer spring to winter because of the warmer temperatures.', ex4_ko = '저는 따뜻한 기온 때문에 겨울보다 봄을 더 좋아해요.',
  ex5 = 'I prefer a light drizzle to a heavy downpour any day.', ex5_ko = '저는 언제나 폭우보다 가랑비를 더 좋아해요.'
