UPDATE sentences SET
  ex1 = 'According to the forecast, there''s a high chance of thunderstorms this evening.', ex1_ko = '예보에 따르면 오늘 저녁 뇌우가 발생할 가능성이 높아요.',
  ex2 = 'According to the forecast, there''s a high chance of heavy snowfall tomorrow morning.', ex2_ko = '예보에 따르면 내일 아침 폭설이 내릴 가능성이 높아요.',
  ex3 = 'According to the forecast, there''s a high chance of strong gusts along the coast tonight.', ex3_ko = '예보에 따르면 오늘 밤 해안을 따라 강한 돌풍이 불 가능성이 높아요.',
  ex4 = 'According to the forecast, there''s a high chance of dense fog during the early morning commute.', ex4_ko = '예보에 따르면 이른 아침 출근 시간대에 짙은 안개가 낄 가능성이 높아요.',
  ex5 = 'According to the forecast, there''s a high chance of flooding in low-lying areas by midweek.', ex5_ko = '예보에 따르면 주중까지 저지대 지역에 홍수가 발생할 가능성이 높아요.'
WHERE id = 's_weather_B1_01';

UPDATE sentences SET
  ex1 = 'You should layer up — the temperature is expected to drop significantly later.', ex1_ko = '옷을 겹쳐 입으세요 — 나중에 기온이 크게 떨어질 것으로 예상돼요.',
  ex2 = 'You should take water with you — the temperature is expected to be very high on the trail.', ex2_ko = '물을 챙기세요 — 등산로의 기온이 매우 높을 것으로 예상돼요.',
  ex3 = 'You should drive slowly — the road surface is expected to be very icy tonight.', ex3_ko = '천천히 운전하세요 — 오늘 밤 도로 표면이 매우 빙판일 것으로 예상돼요.',
  ex4 = 'You should leave early — traffic is expected to be heavy due to the poor weather conditions.', ex4_ko = '일찍 출발하세요 — 악천후로 인해 교통량이 많을 것으로 예상돼요.',
  ex5 = 'You should keep the children indoors — the air quality is expected to be very poor today.', ex5_ko = '아이들을 실내에 두세요 — 오늘 공기 질이 매우 나쁠 것으로 예상돼요.'
WHERE id = 's_weather_B1_02';

UPDATE sentences SET
  ex1 = 'The humidity is making it feel much hotter than it actually is.', ex1_ko = '습도 때문에 실제보다 훨씬 더 덥게 느껴져요.',
  ex2 = 'The wind chill is making it feel much colder than the thermometer suggests.', ex2_ko = '바람 때문에 온도계가 보여주는 것보다 훨씬 더 춥게 느껴져요.',
  ex3 = 'The fog is making it feel much more enclosed than it actually is on the road.', ex3_ko = '안개 때문에 도로가 실제보다 훨씬 더 갑갑하게 느껴져요.',
  ex4 = 'The heavy cloud cover is making it feel much darker than it should be at this time of day.', ex4_ko = '짙은 구름 덮개 때문에 하루 중 이 시간대보다 훨씬 더 어둡게 느껴져요.',
  ex5 = 'The freezing rain is making it feel much more dangerous outside than the temperature alone indicates.', ex5_ko = '얼어붙는 비 때문에 기온만으로 나타나는 것보다 밖이 훨씬 더 위험하게 느껴져요.'
WHERE id = 's_weather_B1_03';

UPDATE sentences SET
  ex1 = 'I would recommend bringing a light jacket in case the weather changes.', ex1_ko = '날씨가 변할 경우를 대비해서 가벼운 재킷을 챙기도록 권해드려요.',
  ex2 = 'I would recommend checking the road conditions before you set off this morning.', ex2_ko = '오늘 아침 출발하기 전에 도로 상태를 확인하도록 권해드려요.',
  ex3 = 'I would recommend keeping an emergency kit in your car during winter months.', ex3_ko = '겨울철에는 차에 비상 키트를 챙겨두도록 권해드려요.',
  ex4 = 'I would recommend avoiding the coastal path today given the strong gale warning in place.', ex4_ko = '오늘은 강풍 경보가 발령 중이니 해안 길을 피하도록 권해드려요.',
  ex5 = 'I would recommend monitoring the flood warnings before travelling through the valley tomorrow.', ex5_ko = '내일 계곡을 통과해 이동하기 전에 홍수 경보를 확인하도록 권해드려요.'
